import { User, Appointment, Dentist, Service, ClinicSettings, TimeSlot, ReportData, AppointmentStatus, UserRole } from '../types';
import { MOCK_USERS, MOCK_APPOINTMENTS, MOCK_DENTISTS, MOCK_SERVICES, MOCK_CLINIC_SETTINGS } from '../constants';
import { getDay, format, addMinutes, isWithinInterval, isSameDay } from 'date-fns';

// --- STORAGE KEYS ---
// Updated to v4 to include Dentist persistence
const STORAGE_KEYS = {
  USERS: 'nexsched_v4_users',
  APPOINTMENTS: 'nexsched_v4_appointments',
  SETTINGS: 'nexsched_v4_settings',
  DENTISTS: 'nexsched_v4_dentists'
};

// --- DATA PERSISTENCE HELPERS ---
const loadData = <T,>(key: string, fallback: T): T => {
  try {
    const item = localStorage.getItem(key);
    if (item) {
      if (key === STORAGE_KEYS.APPOINTMENTS) {
        return JSON.parse(item, (k, v) => {
           if (k === 'start' || k === 'end' || k === 'createdAt' || k === 'time') return new Date(v);
           return v;
        });
      }
      return JSON.parse(item);
    }
  } catch (e) {
    console.warn(`Failed to load ${key} from storage`, e);
  }
  return fallback;
};

const saveData = (key: string, data: any) => {
  try {
    localStorage.setItem(key, JSON.stringify(data));
  } catch (e) {
    console.error(`Failed to save ${key} to storage`, e);
  }
};

// --- IN-MEMORY STATE ---
let users: User[] = loadData(STORAGE_KEYS.USERS, [...MOCK_USERS]);

// Auto-inject developer account
const devAccount = MOCK_USERS.find(u => u.id === 'user-dev');
if (devAccount && !users.some(u => u.id === devAccount.id)) {
    users.push(devAccount);
    saveData(STORAGE_KEYS.USERS, users);
}

let appointments: Appointment[] = loadData(STORAGE_KEYS.APPOINTMENTS, [...MOCK_APPOINTMENTS]);
let clinicSettings: ClinicSettings = loadData(STORAGE_KEYS.SETTINGS, { ...MOCK_CLINIC_SETTINGS });
let dentists: Dentist[] = loadData(STORAGE_KEYS.DENTISTS, [...MOCK_DENTISTS]);
let services: Service[] = [...MOCK_SERVICES];

let currentUserId: string | null = null;

const simulateDelay = <T,>(data: T): Promise<T> => {
  return new Promise(resolve => setTimeout(() => resolve(data), 400));
};

// --- AUTH ---
export const login = (email: string, password: string): Promise<User | null> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  const user = users.find(u => u.email.toLowerCase() === email.toLowerCase() && u.password === password);
  if (user) {
    currentUserId = user.id;
    return simulateDelay(user);
  }
  return simulateDelay(null);
};

export const register = (details: Omit<User, 'id' | 'role' | 'password'> & { password_reg: string }): Promise<{ user: User | null; error?: string }> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  if (users.find(u => u.email.toLowerCase() === details.email.toLowerCase())) {
    return simulateDelay({ user: null, error: "An account with this email already exists." });
  }
  const newUser: User = {
    id: `user-${Date.now()}`,
    email: details.email,
    password: details.password_reg,
    name: details.name,
    phone: details.phone,
    age: details.age,
    gender: details.gender,
    role: UserRole.Patient,
  };
  users.push(newUser);
  saveData(STORAGE_KEYS.USERS, users);
  currentUserId = newUser.id;
  return simulateDelay({ user: newUser });
};

export const getCurrentUser = (): User | null => {
  if (!currentUserId) return null;
  return users.find(u => u.id === currentUserId) || null;
}

export const logout = (): void => {
  currentUserId = null;
};

// --- DATA FETCHING ---
export const getAppointmentsForUser = (userId: string): Promise<Appointment[]> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments.filter(a => a.patientId === userId));
};

export const getAllAppointments = (): Promise<Appointment[]> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments);
};

export const getAllPatients = (): Promise<User[]> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  return simulateDelay(users.filter(u => u.role === 'patient'));
};

export const getDentists = (): Promise<Dentist[]> => {
  dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
  return simulateDelay(dentists);
};

export const getServices = (): Promise<Service[]> => simulateDelay(services);

export const getClinicSettings = (): Promise<ClinicSettings> => {
  clinicSettings = loadData(STORAGE_KEYS.SETTINGS, clinicSettings);
  return simulateDelay(clinicSettings);
};

export const updateClinicSettings = (settings: ClinicSettings): Promise<ClinicSettings> => {
    clinicSettings = { ...settings };
    saveData(STORAGE_KEYS.SETTINGS, clinicSettings);
    return simulateDelay(clinicSettings);
};

// --- DENTIST MUTATIONS ---
export const addDentist = (details: Omit<Dentist, 'id'>): Promise<Dentist> => {
    dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
    const newDentist: Dentist = {
        id: `dentist-${Date.now()}`,
        ...details
    };
    dentists.push(newDentist);
    saveData(STORAGE_KEYS.DENTISTS, dentists);
    return simulateDelay(newDentist);
};

export const deleteDentist = (id: string): Promise<void> => {
    dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
    dentists = dentists.filter(d => d.id !== id);
    saveData(STORAGE_KEYS.DENTISTS, dentists);
    return simulateDelay(undefined);
};

// --- HELPER ---
const parseTime = (timeStr: string, baseDate: Date): Date => {
  const [hours, minutes] = timeStr.split(':').map(Number);
  const d = new Date(baseDate);
  d.setHours(hours, minutes, 0, 0);
  return d;
};

// --- AVAILABILITY ---
export const getAvailableTimeSlots = (date: Date, dentistId: string, serviceId: string): Promise<TimeSlot[]> => {
  clinicSettings = loadData(STORAGE_KEYS.SETTINGS, clinicSettings);
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  if (!clinicSettings.onlineBookingEnabled) return simulateDelay([]);
  const dayOfWeek = getDay(date);
  const workingHours = clinicSettings.workingHours.find(wh => wh.dayOfWeek === dayOfWeek);
  const service = services.find(s => s.id === serviceId);
  if (!workingHours || !workingHours.isOpen || !service) return simulateDelay([]);
  const dayString = format(date, 'yyyy-MM-dd');
  if(clinicSettings.holidays.includes(dayString)) return simulateDelay([]);
  const startTime = parseTime(workingHours.start, date);
  const endTime = parseTime(workingHours.end, date);
  const dentistAppointments = appointments.filter(a => a.dentistId === dentistId && isSameDay(a.start, date) && a.status === AppointmentStatus.Scheduled);
  const allSlots: TimeSlot[] = [];
  let currentTime = startTime;
  while(currentTime < endTime) {
    const slotEnd = addMinutes(currentTime, service.durationMinutes);
    if (slotEnd > endTime) break;
    const isBooked = dentistAppointments.some(appt => 
      isWithinInterval(currentTime, { start: appt.start, end: appt.end }) ||
      isWithinInterval(slotEnd, { start: appt.start, end: appt.end }) ||
      isWithinInterval(appt.start, { start: currentTime, end: slotEnd })
    );
    allSlots.push({ time: new Date(currentTime.getTime()), isAvailable: !isBooked });
    currentTime = addMinutes(currentTime, clinicSettings.slotDurationMinutes);
  }
  return simulateDelay(allSlots);
};

export const bookAppointment = (details: { patientId: string, dentistId: string, serviceId: string, start: Date }): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const service = services.find(s => s.id === details.serviceId);
  if (!service) throw new Error("Service not found");
  const newAppointment: Appointment = {
    id: `apt-${Date.now()}`,
    ...details,
    end: addMinutes(details.start, service.durationMinutes),
    status: AppointmentStatus.Scheduled,
    createdAt: new Date(),
    reminderSent: false,
  };
  appointments.push(newAppointment);
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(newAppointment);
};

export const cancelAppointment = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const appointment = appointments.find(a => a.id === appointmentId);
  if (!appointment) throw new Error("Appointment not found");
  appointment.status = AppointmentStatus.Cancelled;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointment);
  return simulateDelay(appointment);
};

export const updateAppointmentStatus = (appointmentId: string, status: AppointmentStatus): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const appointment = appointments.find(a => a.id === appointmentId);
  if (!appointment) throw new Error("Appointment not found");
  appointment.status = status;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointment);
};

export const sendReminder = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const appointment = appointments.find(a => a.id === appointmentId);
  if (!appointment) throw new Error("Appointment not found");
  appointment.reminderSent = true;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointment);
};

export const getReportData = (): Promise<ReportData> => {
    appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
    const total = appointments.length;
    const noShows = appointments.filter(a => a.status === AppointmentStatus.NoShow).length;
    const completed = appointments.filter(a => a.status === AppointmentStatus.Completed).length;
    const appointmentsByService = services.reduce((acc, service) => {
        acc[service.name] = appointments.filter(a => a.serviceId === service.id).length;
        return acc;
    }, {} as { [serviceName: string]: number });
    const dayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const busiestDays = appointments.reduce((acc, appt) => {
        const day = dayNames[getDay(appt.start)];
        acc[day] = (acc[day] || 0) + 1;
        return acc;
    }, {} as { [day: string]: number });
    return simulateDelay({
        totalAppointments: total,
        noShowRate: total > 0 ? (noShows / total) * 100 : 0,
        attendanceRate: total > 0 ? (completed / total) * 100 : 0,
        appointmentsByService,
        busiestDays
    });
};

