// --- HELPER ---
const parseTime = (timeStr: string, baseDate: Date): Date => {
  const [hours, minutes] = timeStr.split(':').map(Number);
  const d = new Date(baseDate);
  d.setHours(hours, minutes, 0, 0);
  return d;
};

// --- AVAILABILITY ---
export const getAvailableTimeSlots = (date: Date, dentistId: string, serviceId: string): Promise<TimeSlot[]> => {
  clinicSettings = loadData(STORAGE_KEYS.SETTINGS, clinicSettings);
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  if (!clinicSettings.onlineBookingEnabled) return simulateDelay([]);
  const dayOfWeek = getDay(date);
  const workingHours = clinicSettings.workingHours.find(wh => wh.dayOfWeek === dayOfWeek);
  const service = services.find(s => s.id === serviceId);
  if (!workingHours || !workingHours.isOpen || !service) return simulateDelay([]);
  const dayString = format(date, 'yyyy-MM-dd');
  if(clinicSettings.holidays.includes(dayString)) return simulateDelay([]);
  const startTime = parseTime(workingHours.start, date);
  const endTime = parseTime(workingHours.end, date);
  const dentistAppointments = appointments.filter(a => a.dentistId === dentistId && isSameDay(a.start, date) && a.status === AppointmentStatus.Scheduled);
  const allSlots: TimeSlot[] = [];
  let currentTime = startTime;
  while(currentTime < endTime) {
    const slotEnd = addMinutes(currentTime, service.durationMinutes);
    if (slotEnd > endTime) break;
    const isBooked = dentistAppointments.some(appt => 
      isWithinInterval(currentTime, { start: appt.start, end: appt.end }) ||
      isWithinInterval(slotEnd, { start: appt.start, end: appt.end }) ||
      isWithinInterval(appt.start, { start: currentTime, end: slotEnd })
    );
    allSlots.push({ time: new Date(currentTime.getTime()), isAvailable: !isBooked });
    currentTime = addMinutes(currentTime, clinicSettings.slotDurationMinutes);
  }
  return simulateDelay(allSlots);
};

export const bookAppointment = (details: { patientId: string, dentistId: string, serviceId: string, start: Date }): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const service = services.find(s => s.id === details.serviceId);
  if (!service) throw new Error("Service not found");
  const newAppointment: Appointment = {
    id: `apt-${Date.now()}`,
    ...details,
    end: addMinutes(details.start, service.durationMinutes),
    status: AppointmentStatus.Scheduled,
    createdAt: new Date(),
    reminderSent: false,
  };
  appointments.push(newAppointment);
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(newAppointment);
};

export const cancelAppointment = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].status = AppointmentStatus.Cancelled;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const updateAppointmentStatus = (appointmentId: string, status: AppointmentStatus): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].status = status;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const sendReminder = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].reminderSent = true;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const getReportData = (): Promise<ReportData> => {
    appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
    const total = appointments.length;
    const noShows = appointments.filter(a => a.status === AppointmentStatus.NoShow).length;
    const completed = appointments.filter(a => a.status === AppointmentStatus.Completed).length;
    const appointmentsByService = services.reduce((acc, service) => {
        acc[service.name] = appointments.filter(a => a.serviceId === service.id).length;
        return acc;
    }, {} as { [serviceName: string]: number });
    const dayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const busiestDays = appointments.reduce((acc, appt) => {
        const day = dayNames[getDay(appt.start)];
        acc[day] = (acc[day] || 0) + 1;
        return acc;
    }, {} as { [day: string]: number });
    return simulateDelay({
        totalAppointments: total,
        noShowRate: total > 0 ? (noShows / total) * 100 : 0,
        attendanceRate: total > 0 ? (completed / total) * 100 : 0,
        appointmentsByService,
        busiestDays
    });
};

import React, { useState, useEffect, useCallback } from 'react';
import { User, Appointment, Service, Dentist, AppointmentStatus } from '../../types';
import { getAppointmentsForUser, getServices, getDentists, cancelAppointment, sendReminder } from '../../services/mockApi';
import Header from '../Layout/Header';
import Booking from './Booking';
import { format, isSameDay, addDays } from 'date-fns';
import { CalendarIcon, ClockIcon, UserIcon } from '../Shared/Icons';

interface PatientDashboardProps {
  user: User;
  onLogout: () => void;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ user, onLogout }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [dentists, setDentists] = useState<Dentist[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [view, setView] = useState<'appointments' | 'booking'>('appointments');
  const [tomorrowAppt, setTomorrowAppt] = useState<Appointment | null>(null);

  const fetchPatientData = useCallback(async () => {
    setIsLoading(true);
    try {
      const [userAppointments, allServices, allDentists] = await Promise.all([
        getAppointmentsForUser(user.id),
        getServices(),
        getDentists(),
      ]);
      setAppointments(userAppointments);
      setServices(allServices);
      setDentists(allDentists);

      // Check for tomorrow's appointment
      const tomorrow = addDays(new Date(), 1);
      const foundTomorrow = userAppointments.find(a => 
        a.status === AppointmentStatus.Scheduled && 
        isSameDay(new Date(a.start), tomorrow)
      );

      if (foundTomorrow) {
          setTomorrowAppt(foundTomorrow);

          // Auto-trigger SMS Simulation if not sent yet
          if (!foundTomorrow.reminderSent) {
              const serviceName = allServices.find(s => s.id === foundTomorrow.serviceId)?.name || 'Appointment';
              const timeStr = format(new Date(foundTomorrow.start), 'h:mm a');

              // We use a small timeout to let the UI render first
              setTimeout(async () => {
                const smsMessage = `[NexSched] Hello ${user.name.split(' ')[0]}! This is a reminder for your ${serviceName} tomorrow at ${timeStr}. Please arrive 10 mins early. Reply CANCEL to opt-out.`;
                alert(`AUTOMATED SMS REMINDER SENT\n\nTo: ${user.phone}\nMessage: ${smsMessage}`);

                await sendReminder(foundTomorrow.id);
                // Silently update local state
                setAppointments(prev => prev.map(a => a.id === foundTomorrow.id ? {...a, reminderSent: true} : a));
              }, 1000);
          }
      }
    } catch (error) {
      console.error("Failed to fetch patient data", error);
    } finally {
      setIsLoading(false);
    }
  }, [user.id, user.name, user.phone]);

  useEffect(() => {
    fetchPatientData();
  }, [fetchPatientData]);

  const handleBookingSuccess = () => {
    fetchPatientData(); 
    setView('appointments');
  };

  const handleCancelAppointment = async (appointmentId: string) => {
    if (window.confirm("Are you sure you want to cancel this appointment?")) {
        await cancelAppointment(appointmentId);
        fetchPatientData();
        alert("Appointment cancelled successfully.");
    }
  };

  const upcomingAppointments = appointments
    .filter(a => a.status === AppointmentStatus.Scheduled && new Date(a.start) >= new Date())
    .sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

  const pastAppointments = appointments
    .filter(a => new Date(a.start) < new Date())
    .sort((a, b) => new Date(b.start).getTime() - new Date(a.start).getTime());


  const renderAppointments = () => (
    <>
      {/* Tomorrow's Reminder Banner */}
      {tomorrowAppt && (
        <div className="mb-8 bg-brand-blue text-white p-4 rounded-xl shadow-lg flex items-center justify-between animate-pulse">
            <div className="flex items-center">
                <div className="bg-white/20 p-2 rounded-full mr-4">
                    <ClockIcon className="w-6 h-6" />
                </div>
                <div>
                    <h4 className="font-bold text-lg">Appointment Tomorrow!</h4>
                    <p className="text-sm opacity-90">
                        You have a <strong>{services.find(s => s.id === tomorrowAppt.serviceId)?.name}</strong> at <strong>{format(new Date(tomorrowAppt.start), 'h:mm a')}</strong>.
                        A reminder was sent to <strong>{user.phone}</strong>.
                    </p>
                </div>
            </div>
            <button 
                onClick={() => setTomorrowAppt(null)}
                className="text-white/70 hover:text-white"
            >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
            </button>
        </div>
      )}

      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Your Appointments</h2>
        <button 
            onClick={() => setView('booking')}
            className="px-6 py-2 bg-brand-blue text-white font-semibold rounded-lg shadow-md hover:bg-brand-blue-dark focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-blue transition duration-150"
        >
            Book New Appointment
        </button>
      </div>

      {isLoading ? (
        <p>Loading appointments...</p>
      ) : (
        <div>
          <h3 className="text-xl font-semibold text-gray-700 mb-4">Upcoming</h3>
          {upcomingAppointments.length > 0 ? (
            <div className="space-y-4">
              {upcomingAppointments.map(app => {
                const dentist = dentists.find(d => d.id === app.dentistId);
                const service = services.find(s => s.id === app.serviceId);
                const isTomorrow = isSameDay(new Date(app.start), addDays(new Date(), 1));

                return (
                  <div key={app.id} className={`bg-white p-4 rounded-lg shadow-sm border flex flex-col sm:flex-row justify-between items-start sm:items-center ${isTomorrow ? 'border-brand-blue ring-1 ring-brand-blue ring-opacity-50' : 'border-gray-200'}`}>
                    <div>
                      <div className="flex items-center">
                        <p className="font-bold text-brand-blue-dark text-lg">{service?.name}</p>
                        {isTomorrow && <span className="ml-2 px-2 py-0.5 bg-brand-blue text-white text-[10px] uppercase font-bold rounded">Tomorrow</span>}
                      </div>
                      <div className="text-gray-600 mt-2 space-y-1 text-sm">
                        <p className="flex items-center"><UserIcon className="w-4 h-4 mr-2 text-brand-blue"/> {dentist?.name}</p>
                        <p className="flex items-center"><CalendarIcon className="w-4 h-4 mr-2 text-brand-blue"/> {format(new Date(app.start), 'eeee, MMMM d, yyyy')}</p>
                        <p className="flex items-center"><ClockIcon className="w-4 h-4 mr-2 text-brand-blue"/> {format(new Date(app.start), 'h:mm a')} - {format(new Date(app.end), 'h:mm a')}</p>
                      </div>
                    </div>
                    <div className="mt-4 sm:mt-0">
                      <button onClick={() => handleCancelAppointment(app.id)} className="text-sm px-4 py-1 bg-red-100 text-red-700 rounded-full hover:bg-red-200">Cancel</button>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div className="text-center py-8 bg-white rounded-lg border-dashed border-2 border-gray-300">
                <p className="text-gray-500">You have no upcoming appointments.</p>
            </div>
          )}

          <h3 className="text-xl font-semibold text-gray-700 mt-8 mb-4">History</h3>
          {pastAppointments.length > 0 ? (
              <div className="space-y-4">
                 {pastAppointments.map(app => {
                  const dentist = dentists.find(d => d.id === app.dentistId);
                  const service = services.find(s => s.id === app.serviceId);
                  const statusColors = {
                    [AppointmentStatus.Completed]: 'text-green-700 bg-green-100',
                    [AppointmentStatus.Cancelled]: 'text-gray-700 bg-gray-100',
                    [AppointmentStatus.NoShow]: 'text-red-700 bg-red-100',
                    [AppointmentStatus.Scheduled]: 'text-sky-700 bg-sky-100',
                  }
                  return (
                    <div key={app.id} className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 opacity-70">
                      <div className="flex justify-between items-start">
                         <div>
                            <p className="font-bold text-gray-700 text-lg">{service?.name}</p>
                            <p className="text-sm text-gray-500">{dentist?.name}</p>
                            <p className="text-sm text-gray-500">{format(new Date(app.start), 'MMMM d, yyyy')}</p>
                         </div>
                         <span className={`px-3 py-1 text-xs font-semibold rounded-full ${statusColors[app.status]}`}>
                            {app.status.charAt(0).toUpperCase() + app.status.slice(1)}
                        </span>
                      </div>
                    </div>
                  )
                 })}
              </div>
          ): (
            <div className="text-center py-8 bg-white rounded-lg border-dashed border-2 border-gray-300">
                <p className="text-gray-500">No appointment history.</p>
            </div>
          )}
        </div>
      )}
    </>
  );

  return (
    <div>
      <Header user={user} onLogout={onLogout} />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        {view === 'appointments' ? (
          renderAppointments()
        ) : (
          <Booking 
            user={user} 
            dentists={dentists}
            services={services}
            onBookingSuccess={handleBookingSuccess}
            onBack={() => setView('appointments')}
          />
        )}
      </main>
    </div>
  );
};

export default PatientDashboard;

