let dentists: Dentist[] = loadData(STORAGE_KEYS.DENTISTS, [...MOCK_DENTISTS]);
let services: Service[] = [...MOCK_SERVICES];

let currentUserId: string | null = null;

const simulateDelay = <T,>(data: T): Promise<T> => {
  return new Promise(resolve => setTimeout(() => resolve(data), 400));
};

// --- AUTH ---
export const login = (email: string, password: string): Promise<User | null> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  const user = users.find(u => u.email.toLowerCase() === email.toLowerCase() && u.password === password);
  if (user) {
    currentUserId = user.id;
    return simulateDelay(user);
  }
  return simulateDelay(null);
};

export const register = (details: Omit<User, 'id' | 'role' | 'password'> & { password_reg: string }): Promise<{ user: User | null; error?: string }> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  if (users.find(u => u.email.toLowerCase() === details.email.toLowerCase())) {
    return simulateDelay({ user: null, error: "An account with this email already exists." });
  }
  const newUser: User = {
    id: `user-${Date.now()}`,
    email: details.email,
    password: details.password_reg,
    name: details.name,
    phone: details.phone,
    age: details.age,
    gender: details.gender,
    role: UserRole.Patient,
  };
  users.push(newUser);
  saveData(STORAGE_KEYS.USERS, users);
  currentUserId = newUser.id;
  return simulateDelay({ user: newUser });
};

export const getCurrentUser = (): User | null => {
  if (!currentUserId) return null;
  return users.find(u => u.id === currentUserId) || null;
}

export const logout = (): void => {
  currentUserId = null;
};

