import React, { useState, useEffect, useCallback } from 'react';
import { User, Appointment, Service, Dentist, AppointmentStatus } from '../../types';
import { getAppointmentsForUser, getServices, getDentists, cancelAppointment, sendSmsReminder, sendEmailReminder } from '../../services/mockApi';
import Header from '../Layout/Header';
import Booking from './Booking';
import { format, isSameDay, addDays } from 'date-fns';
import { CalendarIcon, ClockIcon, UserIcon } from '../Shared/Icons';

interface PatientDashboardProps {
  user: User;
  onLogout: () => void;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ user, onLogout }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [dentists, setDentists] = useState<Dentist[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [view, setView] = useState<'appointments' | 'booking'>('appointments');
  const [activeReminder, setActiveReminder] = useState<Appointment | null>(null);

  const fetchPatientData = useCallback(async () => {
    setIsLoading(true);
    try {
      const [userAppointments, allServices, allDentists] = await Promise.all([
        getAppointmentsForUser(user.id),
        getServices(),
        getDentists(),
      ]);
      setAppointments(userAppointments);
      setServices(allServices);
      setDentists(allDentists);

      // SCAN FOR PENDING REMINDERS (Next 48 hours)
      const now = new Date();
      const next48h = addDays(now, 2);

      const pendingReminder = userAppointments.find(a => 
        a.status === AppointmentStatus.Scheduled && 
        new Date(a.start) > now && 
        new Date(a.start) <= next48h &&
        (!a.smsReminderSent || !a.emailReminderSent)
      );

      if (pendingReminder) {
          setActiveReminder(pendingReminder);

          const serviceName = allServices.find(s => s.id === pendingReminder.serviceId)?.name || 'Appointment';
          const timeStr = format(new Date(pendingReminder.start), 'eeee, MMM d @ h:mm a');
          const firstName = user.name.split(' ')[0];

          // Simulation of the "Reminder Engine"
          setTimeout(async () => {
              if (!pendingReminder.smsReminderSent) {
                alert(`[VIRTUAL SMS DISPATCH]\nTo: ${user.phone}\nMessage: "Hi ${firstName}! Reminder for your ${serviceName} on ${timeStr} at NexSched. Please arrive early!"`);
                await sendSmsReminder(pendingReminder.id);
              }

              if (!pendingReminder.emailReminderSent) {
                alert(`[VIRTUAL EMAIL DISPATCH]\nTo: ${user.email}\nSubject: Appointment Reminder - NexSched\nBody: "Dear ${user.name}, we look forward to seeing you for your ${serviceName} on ${timeStr}."`);
                await sendEmailReminder(pendingReminder.id);
              }

              // Refresh local data to show "Sent" status
              const updated = await getAppointmentsForUser(user.id);
              setAppointments(updated);
          }, 1500);
      }
    } catch (error) {
      console.error("Failed to fetch patient data", error);
    } finally {
      setIsLoading(false);
    }
  }, [user.id, user.name, user.phone, user.email]);

  useEffect(() => {
    fetchPatientData();
  }, [fetchPatientData]);

  const handleBookingSuccess = () => {
    fetchPatientData(); 
    setView('appointments');
  };

  const handleCancelAppointment = async (appointmentId: string) => {
    if (window.confirm("Are you sure you want to cancel this appointment?")) {
        await cancelAppointment(appointmentId);
        fetchPatientData();
        alert("Appointment cancelled. A cancellation notice was sent to your email.");
    }
  };

  const upcomingAppointments = appointments
    .filter(a => a.status === AppointmentStatus.Scheduled && new Date(a.start) >= new Date())
    .sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

  const pastAppointments = appointments
    .filter(a => new Date(a.start) < new Date())
    .sort((a, b) => new Date(b.start).getTime() - new Date(a.start).getTime());

  return (
    <div>
      <Header user={user} onLogout={onLogout} />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        {view === 'appointments' ? (
          <>
            {/* Reminder Engine Active Alert */}
            {activeReminder && (
              <div className="mb-8 bg-green-600 text-white p-4 rounded-xl shadow-lg flex items-center justify-between border-b-4 border-green-800">
                  <div className="flex items-center">
                      <div className="bg-white/20 p-2 rounded-full mr-4">
                          <svg className="w-6 h-6 animate-bounce" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 17h5l-1.405-1.405A2.032 2.032 0 0118 14.158V11a6.002 6.002 0 00-4-5.659V5a2 2 0 10-4 0v.341C7.67 6.165 6 8.388 6 11v3.159c0 .538-.214 1.055-.595 1.436L4 17h5m6 0v1a3 3 0 11-6 0v-1m6 0H9" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                      </div>
                      <div>
                          <h4 className="font-bold text-lg">Reminder Engine Dispatching...</h4>
                          <p className="text-sm opacity-90">
                              Sending alerts to <strong>{user.email}</strong> and <strong>{user.phone}</strong> for your next visit.
                          </p>
                      </div>
                  </div>
                  <button onClick={() => setActiveReminder(null)} className="text-white/70 hover:text-white">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                  </button>
              </div>
            )}

            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-800">Patient Dashboard</h2>
              <button onClick={() => setView('booking')} className="px-6 py-2 bg-brand-blue text-white font-semibold rounded-lg shadow-md hover:bg-brand-blue-dark">
                  Book New Appointment
              </button>
            </div>

            {isLoading ? (
              <p>Loading your medical records...</p>
            ) : (
              <div>
                <h3 className="text-xl font-semibold text-gray-700 mb-4">Upcoming Care</h3>
