import React, { useState, useEffect } from 'react';
import { Appointment, AppointmentStatus, User, Service } from '../../types';
import { getAllAppointments, getAllPatients, getServices, sendSmsReminder, sendEmailReminder } from '../../services/mockApi';
import { format, addDays, isSameDay } from 'date-fns';

const Reminders: React.FC = () => {
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [patients, setPatients] = useState<User[]>([]);
    const [services, setServices] = useState<Service[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    const fetchReminderData = async () => {
        setIsLoading(true);
        try {
            const [apptData, patientData, serviceData] = await Promise.all([
                getAllAppointments(),
                getAllPatients(),
                getServices()
            ]);

            // Show upcoming 7 days for admin to review
            const now = new Date();
            const weekOut = addDays(now, 7);

            const upcoming = apptData.filter(a => 
                a.status === AppointmentStatus.Scheduled &&
                new Date(a.start) >= now &&
                new Date(a.start) <= weekOut
            );

            upcoming.sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

            setAppointments(upcoming);
            setPatients(patientData);
            setServices(serviceData);
        } catch (error) {
            console.error("Failed to load reminder data", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchReminderData();
    }, []);

    const handleReSend = async (appointment: Appointment, channel: 'SMS' | 'EMAIL') => {
        const patient = patients.find(p => p.id === appointment.patientId);
        const service = services.find(s => s.id === appointment.serviceId);
        if (!patient) return;

        if (channel === 'SMS') {
            const msg = `[SMS RE-SEND] To: ${patient.phone} for ${service?.name}`;
            alert(msg);
            await sendSmsReminder(appointment.id);
        } else {
            const msg = `[EMAIL RE-SEND] To: ${patient.email} for ${service?.name}`;
            alert(msg);
            await sendEmailReminder(appointment.id);
        }
        fetchReminderData();
    };

    if (isLoading) return <p className="p-4">Syncing notification logs...</p>;

    return (
        <div className="bg-white p-6 rounded-lg shadow-lg">
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800">Notification Hub</h2>
                    <p className="text-sm text-gray-500">Monitoring Email & SMS reminders for the next 7 days</p>
                </div>
                <button onClick={fetchReminderData} className="px-4 py-2 bg-brand-gray-light text-brand-blue-dark rounded-md text-sm font-semibold hover:bg-brand-gray border border-brand-blue/10">
                    Refresh Statuses
                </button>
            </div>

            {appointments.length === 0 ? (
                <div className="text-center py-10 bg-gray-50 rounded-lg border-2 border-dashed border-gray-200">
                    <p className="text-gray-500">No upcoming appointments for automated reminders.</p>
                </div>
            ) : (
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient & Visit</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Schedule</th>
                                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase">Email Status</th>
                                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase">SMS Status</th>
                                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Manual Trigger</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {appointments.map(appt => {
                                const patient = patients.find(p => p.id === appt.patientId);
                                const service = services.find(s => s.id === appt.serviceId);

                                return (
                                    <tr key={appt.id} className="hover:bg-gray-50 transition-colors">
                                        <td className="px-6 py-4">
                                            <div className="text-sm font-bold text-gray-900">{patient?.name || 'Guest'}</div>
                                            <div className="text-xs text-brand-blue">{service?.name}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm text-gray-900 font-semibold">{format(new Date(appt.start), 'MMM d, h:mm a')}</div>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            {appt.emailReminderSent ? (
                                                <span className="px-2 py-1 text-xs font-bold rounded bg-green-100 text-green-700">Delivered</span>
                                            ) : (
                                                <span className="px-2 py-1 text-xs font-bold rounded bg-yellow-100 text-yellow-700">Queued</span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            {appt.smsReminderSent ? (
                                                <span className="px-2 py-1 text-xs font-bold rounded bg-green-100 text-green-700">Sent</span>
                                            ) : (
                                                <span className="px-2 py-1 text-xs font-bold rounded bg-yellow-100 text-yellow-700">Queued</span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-right space-x-2">
                                            <button onClick={() => handleReSend(appt, 'EMAIL')} className="text-[10px] font-bold text-brand-blue hover:underline">Re-Email</button>
                                            <button onClick={() => handleReSend(appt, 'SMS')} className="text-[10px] font-bold text-brand-blue hover:underline">Re-SMS</button>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
};

export default Reminders;

import React, { useState, useMemo, useEffect } from 'react';
import { User, Dentist, Service, TimeSlot } from '../../types';
import { getAvailableTimeSlots, bookAppointment, register, sendSmsReminder, sendEmailReminder } from '../../services/mockApi';
import { format, endOfMonth, eachDayOfInterval, getDay, isToday, isBefore, addMonths } from 'date-fns';
import { ChevronLeftIcon, ChevronRightIcon } from '../Shared/Icons';
import Modal from '../Shared/Modal';

interface BookingProps {
    user?: User;
    dentists: Dentist[];
    services: Service[];
    onBookingSuccess: () => void;
    onBack?: () => void;
}

const Booking: React.FC<BookingProps> = ({ user, dentists, services, onBookingSuccess, onBack }) => {
    const [currentMonth, setCurrentMonth] = useState(new Date());
    const [selectedDate, setSelectedDate] = useState<Date | null>(null);
    const [selectedDentist, setSelectedDentist] = useState<string>(dentists[0]?.id || '');
    const [selectedService, setSelectedService] = useState<string>('');
    const [timeSlots, setTimeSlots] = useState<TimeSlot[]>([]);
    const [isLoadingSlots, setIsLoadingSlots] = useState(false);
    const [selectedTime, setSelectedTime] = useState<Date | null>(null);
    const [isConfirming, setIsConfirming] = useState(false);
    const [isBooking, setIsBooking] = useState(false);

    // Guest State
    const [guestDetails, setGuestDetails] = useState({
        name: '',
        email: '',
        phone: '',
        age: '',
        gender: 'Male'
    });

    const filteredServices = useMemo(() => {
        const dentist = dentists.find(d => d.id === selectedDentist);
        if (!dentist || !dentist.serviceIds) return services;
        return services.filter(s => dentist.serviceIds!.includes(s.id));
    }, [selectedDentist, dentists, services]);

    useEffect(() => {
        if (filteredServices.length > 0) {
            if (!selectedService || !filteredServices.find(s => s.id === selectedService)) {
                setSelectedService(filteredServices[0].id);
            }
        } else {
            setSelectedService('');
        }
    }, [filteredServices, selectedService]);

    const firstDayOfMonth = useMemo(() => new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1), [currentMonth]);
    const lastDayOfMonth = useMemo(() => endOfMonth(currentMonth), [currentMonth]);
    const daysInMonth = useMemo(() => eachDayOfInterval({ start: firstDayOfMonth, end: lastDayOfMonth }), [firstDayOfMonth, lastDayOfMonth]);
    const startingDayIndex = getDay(firstDayOfMonth);

    useEffect(() => {
        if (!selectedDentist && dentists.length > 0) setSelectedDentist(dentists[0].id);
    }, [dentists]);

    useEffect(() => {
        if (selectedDate && selectedDentist && selectedService) {
            const fetchSlots = async () => {
                setIsLoadingSlots(true);
                setTimeSlots([]);
                const slots = await getAvailableTimeSlots(selectedDate, selectedDentist, selectedService);
                setTimeSlots(slots);
                setIsLoadingSlots(false);
            };
            fetchSlots();
        }
    }, [selectedDate, selectedDentist, selectedService]);

    const todayStart = new Date();
    todayStart.setHours(0, 0, 0, 0);

    const handleDateClick = (day: Date) => {
        if (isBefore(day, todayStart)) return;
        setSelectedDate(day);
        setSelectedTime(null);
    };

    const handleBookAppointment = async () => {
        if (!selectedTime || !selectedDentist || !selectedService) return;

        setIsBooking(true);
        try {
            let bookingUserId = user?.id;
            let finalUser: User | null = user || null;

            if (!bookingUserId) {
                if (!guestDetails.name || !guestDetails.email || !guestDetails.phone || !guestDetails.age) {
                    alert("Contact information is required for appointment reminders.");
                    setIsBooking(false);
                    return;
                }

                const regResult = await register({
                    name: guestDetails.name,
                    email: guestDetails.email,
                    phone: guestDetails.phone,
                    age: parseInt(guestDetails.age) || 30,
                    gender: guestDetails.gender as any,
                    password_reg: 'Welcome123!'
                });

                if (regResult.error || !regResult.user) {
                    alert(regResult.error || "Registration failed.");
                    setIsBooking(false);
                    return;
                }
                bookingUserId = regResult.user.id;
                finalUser = regResult.user;
            }

            const appt = await bookAppointment({
                patientId: bookingUserId,
                dentistId: selectedDentist,
                serviceId: selectedService,
                start: selectedTime
            });

            // SIMULATE IMMEDIATE CONFIRMATION ALERT
            if (finalUser) {
                const srv = services.find(s => s.id === selectedService)?.name;
                const timeStr = format(selectedTime, 'h:mm a');

                alert(`[IMMEDIATE CONFIRMATION SENT]\nSMS to: ${finalUser.phone}\nEmail to: ${finalUser.email}\n\nMessage: "Your booking for ${srv} at ${timeStr} is confirmed. We will remind you 24h before."`);

                // Track these as sent
                await sendSmsReminder(appt.id);
                await sendEmailReminder(appt.id);
            }

            onBookingSuccess();
        } catch (error) {
            console.error("Booking failed", error);
            alert("Failed to book appointment. Please try again.");
        } finally {
            setIsBooking(false);
            setIsConfirming(false);
        }
    };

    return (
        <div className="bg-white p-6 rounded-lg shadow-lg">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">Book Appointment</h2>
                {onBack && <button onClick={onBack} className="text-sm text-brand-blue hover:underline">Back to Dashboard</button>}
            </div>

            <div className="bg-brand-blue-light/50 p-3 rounded-md mb-6 border border-brand-blue/10 flex items-center gap-2">
                <svg className="w-5 h-5 text-brand-blue" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                <p className="text-xs text-brand-blue-dark font-medium">Automatic reminders will be sent to your provided phone and email 24h before your visit.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <div className="md:col-span-1 space-y-4">
                    <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Provider</label>
                        <select id="dentist" value={selectedDentist} onChange={e => setSelectedDentist(e.target.value)} className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-brand-blue focus:border-brand-blue sm:text-sm rounded-md shadow-sm">
                            {dentists.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Requested Service</label>
                        <select id="service" value={selectedService} onChange={e => setSelectedService(e.target.value)} className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-brand-blue focus:border-brand-blue sm:text-sm rounded-md shadow-sm">
                            {filteredServices.length > 0 ? filteredServices.map(s => (
                                <option key={s.id} value={s.id}>{s.name}</option>
                            )) : <option value="">No services available</option>}
                        </select>
                    </div>
                </div>

                <div className="md:col-span-2">
                    <div className="flex items-center justify-between mb-4">
                        <button onClick={() => setCurrentMonth(addMonths(currentMonth, -1))} className="p-2 rounded-full hover:bg-gray-100"><ChevronLeftIcon className="w-5 h-5" /></button>
                        <h3 className="text-lg font-semibold">{format(currentMonth, 'MMMM yyyy')}</h3>
                        <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))} className="p-2 rounded-full hover:bg-gray-100"><ChevronRightIcon className="w-5 h-5" /></button>
                    </div>
                    <div className="grid grid-cols-7 gap-1 text-center text-xs text-gray-500 font-bold">
                        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => <div key={day}>{day}</div>)}
                    </div>
                    <div className="grid grid-cols-7 gap-1 mt-2">
                        {Array.from({ length: startingDayIndex }).map((_, i) => <div key={`empty-${i}`} />)}
                        {daysInMonth.map(day => {
                            const isPast = isBefore(day, todayStart);
                            const isSelected = selectedDate && format(day, 'yyyy-MM-dd') === format(selectedDate, 'yyyy-MM-dd');
                            return (
                                <div key={day.toString()} className="flex justify-center items-center">
                                    <button 
                                        onClick={() => handleDateClick(day)}
                                        disabled={isPast}
                                        className={`w-10 h-10 rounded-lg transition-all duration-200 border ${
                                            isPast ? 'text-gray-300 border-transparent cursor-not-allowed' : 
                                            isSelected ? 'bg-brand-blue text-white border-brand-blue shadow-md' :
                                            isToday(day) ? 'text-brand-blue font-black border-brand-blue/20' : 'hover:bg-brand-blue-light border-gray-50'
                                        }`}
                                    >
                                        {format(day, 'd')}
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {selectedDate && (
                <div className="mt-8">
                    <h3 className="text-lg font-semibold mb-4">Available Appointments: {format(selectedDate, 'MMM d, yyyy')}</h3>
                    {isLoadingSlots ? <p className="text-sm animate-pulse text-gray-400">Syncing provider availability...</p> : (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
                            {timeSlots.filter(s => s.isAvailable).length > 0 ? timeSlots.filter(s => s.isAvailable).map(slot => (
                                <button
                                    key={slot.time.toISOString()}
                                    onClick={() => setSelectedTime(slot.time)}
                                    className={`p-2 rounded-md text-sm font-medium border transition-all ${selectedTime?.getTime() === slot.time.getTime() ? 'bg-brand-blue text-white border-brand-blue shadow-inner' : 'bg-white hover:border-brand-blue text-gray-700'}`}
                                >
                                    {format(slot.time, 'h:mm a')}
                                </button>
                            )) : <p className="col-span-full text-gray-500 italic">Fully booked. Try another date.</p>}
                        </div>
                    )}
                </div>
            )}

            {selectedTime && (
                <div className="mt-8 flex justify-end">
                    <button onClick={() => setIsConfirming(true)} className="px-8 py-3 bg-brand-blue text-white font-bold rounded-lg shadow-lg hover:bg-brand-blue-dark transition-all transform hover:scale-105 active:scale-95">
                        {user ? 'Confirm Appointment' : 'Review & Add Details'}
                    </button>
                </div>
            )}

            <Modal isOpen={isConfirming} onClose={() => setIsConfirming(false)} title="Finalize Booking">
                <div className="space-y-4">
                    <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
                        <p className="text-xs font-black text-gray-400 uppercase mb-2">Visit Summary</p>
                        <p className="text-sm"><strong>Treatment:</strong> {services.find(s => s.id === selectedService)?.name}</p>
                        <p className="text-sm"><strong>Provider:</strong> {dentists.find(d => d.id === selectedDentist)?.name}</p>
                        <p className="text-sm"><strong>Schedule:</strong> {selectedDate && format(selectedDate, 'MMM d')} @ {selectedTime && format(selectedTime, 'h:mm a')}</p>
                    </div>

                    {!user && (
                        <div className="pt-2">
                            <h4 className="font-bold text-gray-800 mb-2">Contact for Reminders</h4>
                            <p className="text-[10px] text-gray-500 mb-3">Your phone and email are required to send automated appointment alerts.</p>
                            <div className="space-y-3">
                                <input 
                                    type="text" 
                                    placeholder="Full Name" 
                                    className="w-full border p-2 rounded text-sm"
                                    value={guestDetails.name} 
                                    onChange={e => setGuestDetails({...guestDetails, name: e.target.value})}
                                />
                                <input 
                                    type="email" 
                                    placeholder="Email Address" 
                                    className="w-full border p-2 rounded text-sm"
                                    value={guestDetails.email} 
                                    onChange={e => setGuestDetails({...guestDetails, email: e.target.value})}
                                />
                                <input 
                                    type="tel" 
                                    placeholder="Phone (SMS enabled)" 
                                    className="w-full border p-2 rounded text-sm"
                                    value={guestDetails.phone} 
                                    onChange={e => setGuestDetails({...guestDetails, phone: e.target.value})}
                                />
                                <div className="grid grid-cols-2 gap-2">
                                    <input 
                                        type="number" 
                                        placeholder="Age" 
                                        className="w-full border p-2 rounded text-sm"
                                        value={guestDetails.age} 
                                        onChange={e => setGuestDetails({...guestDetails, age: e.target.value})}
                                    />
                                    <select 
                                        className="w-full border p-2 rounded text-sm"
                                        value={guestDetails.gender} 
                                        onChange={e => setGuestDetails({...guestDetails, gender: e.target.value})}
                                    >
                                        <option>Male</option>
                                        <option>Female</option>
                                    </select>
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="flex justify-end gap-3 mt-8">
                        <button onClick={() => setIsConfirming(false)} className="px-4 py-2 text-gray-500 font-semibold">Back</button>
                        <button onClick={handleBookAppointment} disabled={isBooking} className="px-6 py-2 bg-brand-blue text-white rounded-md font-bold disabled:bg-gray-400">
                            {isBooking ? 'Finalizing...' : 'Book & Notify Me'}
                        </button>
                    </div>
                </div>
            </Modal>
        </div>
    );
};

