export const getReportData = (): Promise<ReportData> => {
    appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
    const total = appointments.length;
    const noShows = appointments.filter(a => a.status === AppointmentStatus.NoShow).length;
    const completed = appointments.filter(a => a.status === AppointmentStatus.Completed).length;
    const appointmentsByService = services.reduce((acc, service) => {
        acc[service.name] = appointments.filter(a => a.serviceId === service.id).length;
        return acc;
    }, {} as { [serviceName: string]: number });
    const dayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const busiestDays = appointments.reduce((acc, appt) => {
        const day = dayNames[getDay(appt.start)];
        acc[day] = (acc[day] || 0) + 1;
        return acc;
    }, {} as { [day: string]: number });
    return simulateDelay({
        totalAppointments: total,
        noShowRate: total > 0 ? (noShows / total) * 100 : 0,
        attendanceRate: total > 0 ? (completed / total) * 100 : 0,
        appointmentsByService,
        busiestDays
    });
};

import React, { useState, useMemo, useEffect } from 'react';
import { Appointment, AppointmentStatus, Dentist, Service, User } from '../../types';
import { getAllAppointments, getDentists, getServices, getAllPatients, updateAppointmentStatus, approveAppointment } from '../../services/mockApi';
import { format, endOfMonth, eachDayOfInterval, getDay, isToday, addMonths, isSameDay, startOfMonth } from 'date-fns';
import { ChevronLeftIcon, ChevronRightIcon, CalendarIcon, UserIcon, ClockIcon } from '../Shared/Icons';
import Modal from '../Shared/Modal';

const statusColors: { [key in AppointmentStatus]: { bg: string, text: string } } = {
  [AppointmentStatus.Pending]: { bg: 'bg-amber-100', text: 'text-amber-700' },
  [AppointmentStatus.Scheduled]: { bg: 'bg-sky-100', text: 'text-sky-700' },
  [AppointmentStatus.Completed]: { bg: 'bg-green-100', text: 'text-green-700' },
  [AppointmentStatus.Cancelled]: { bg: 'bg-gray-100', text: 'text-gray-700' },
  [AppointmentStatus.NoShow]: { bg: 'bg-red-100', text: 'text-red-700' },
};

const FullCalendar: React.FC = () => {
    const [currentMonth, setCurrentMonth] = useState(new Date());
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [dentists, setDentists] = useState<Dentist[]>([]);
    const [services, setServices] = useState<Service[]>([]);
    const [patients, setPatients] = useState<User[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedAppointment, setSelectedAppointment] = useState<Appointment | null>(null);
    const [isUpdating, setIsUpdating] = useState(false);

    const fetchData = async () => {
        setIsLoading(true);
        try {
            const [apptData, dentistData, serviceData, patientData] = await Promise.all([
                getAllAppointments(),
                getDentists(),
                getServices(),
                getAllPatients()
            ]);
            setAppointments(apptData);
            setDentists(dentistData);
            setServices(serviceData);
            setPatients(patientData);
        } catch (error) {
            console.error("Failed to load calendar data", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData();
    }, []);

    const firstDayOfMonth = useMemo(() => startOfMonth(currentMonth), [currentMonth]);
    const lastDayOfMonth = useMemo(() => endOfMonth(currentMonth), [currentMonth]);
    const daysInMonth = useMemo(() => eachDayOfInterval({ start: firstDayOfMonth, end: lastDayOfMonth }), [firstDayOfMonth, lastDayOfMonth]);
    const startingDayIndex = getDay(firstDayOfMonth);

    const handleApprove = async () => {
        if (!selectedAppointment) return;
        setIsUpdating(true);
        try {
            await approveAppointment(selectedAppointment.id);
            setSelectedAppointment(null);
            fetchData();
        } catch (error) {
            alert("Failed to approve appointment.");
        } finally {
            setIsUpdating(false);
        }
    }

    const handleStatusUpdate = async (newStatus: AppointmentStatus) => {
        if (!selectedAppointment) return;
        setIsUpdating(true);
        await updateAppointmentStatus(selectedAppointment.id, newStatus);
        setSelectedAppointment(null);
        setIsUpdating(false);
        fetchData(); 
    };

    const getPatientName = (id: string) => patients.find(p => p.id === id)?.name || 'Unknown Patient';
    const getDentistName = (id: string) => dentists.find(d => d.id === id)?.name || 'Unknown Dentist';
    const getServiceName = (id: string) => services.find(s => s.id === id)?.name || 'Unknown Service';

    return (
        <div className="bg-white p-6 rounded-lg shadow-lg">
             <div className="flex justify-between items-center mb-6">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800">Clinic Calendar</h2>
                    <p className="text-xs text-amber-600 font-bold flex items-center mt-1">
                        <span className="w-2 h-2 bg-amber-500 rounded-full mr-1"></span>
                        {appointments.filter(a => a.status === AppointmentStatus.Pending).length} Awaiting Approval
                    </p>
                </div>
                <div className="flex items-center space-x-4">
                     <button onClick={() => setCurrentMonth(addMonths(currentMonth, -1))} className="p-2 rounded-full hover:bg-gray-100"><ChevronLeftIcon className="w-5 h-5" /></button>
                     <span className="text-lg font-semibold w-40 text-center">{format(currentMonth, 'MMMM yyyy')}</span>
                     <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))} className="p-2 rounded-full hover:bg-gray-100"><ChevronRightIcon className="w-5 h-5" /></button>
                </div>
            </div>

            {isLoading ? <p>Loading calendar...</p> : (
                <>
                    <div className="grid grid-cols-7 gap-px bg-gray-200 border border-gray-200 rounded-lg overflow-hidden">
                        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                            <div key={day} className="bg-gray-50 py-2 text-center text-xs font-semibold text-gray-500 uppercase tracking-wide">
                                {day}
                            </div>
                        ))}

                        {Array.from({ length: startingDayIndex }).map((_, i) => (
                             <div key={`empty-${i}`} className="bg-white h-32 md:h-40" />
                        ))}

                        {daysInMonth.map(day => {
                            const dayAppointments = appointments.filter(a => isSameDay(new Date(a.start), day));
                            dayAppointments.sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

                            return (
                                <div key={day.toString()} className={`bg-white h-32 md:h-40 p-2 border-t border-r border-gray-100 flex flex-col ${isToday(day) ? 'bg-blue-50' : ''}`}>
                                    <span className={`text-sm font-semibold mb-1 ${isToday(day) ? 'text-brand-blue' : 'text-gray-700'}`}>
                                        {format(day, 'd')}
                                    </span>
                                    <div className="flex-1 overflow-y-auto space-y-1 custom-scrollbar">
                                        {dayAppointments.map(appt => {
                                            const dentist = dentists.find(d => d.id === appt.dentistId);
                                            const color = dentist?.color || '#3182CE'; 
                                            const isPending = appt.status === AppointmentStatus.Pending;

                                            return (
                                                <button
                                                    key={appt.id}
                                                    onClick={() => setSelectedAppointment(appt)}
                                                    className={`w-full text-left px-2 py-1 rounded text-[10px] md:text-xs text-white truncate shadow-sm hover:opacity-80 transition-opacity ${isPending ? 'ring-2 ring-amber-400 ring-offset-1 border-2 border-amber-500' : ''}`}
                                                    style={{ backgroundColor: color }}
                                                    title={`${isPending ? '[PENDING] ' : ''}${format(new Date(appt.start), 'h:mm a')} - ${getPatientName(appt.patientId)}`}
                                                >
                                                    {isPending && '⚠️ '}{format(new Date(appt.start), 'h:mm a')} {getPatientName(appt.patientId)}
                                                </button>
                                            );
                                        })}
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </>
            )}

            <Modal isOpen={!!selectedAppointment} onClose={() => setSelectedAppointment(null)} title="Appointment Details">
                {selectedAppointment && (
                    <div className="space-y-4">
                        <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
                             <div className="flex justify-between items-start mb-2">
                                <h4 className="font-bold text-lg text-gray-800">{getServiceName(selectedAppointment.serviceId)}</h4>
                                <span className={`px-2 py-1 rounded-full text-xs font-semibold ${statusColors[selectedAppointment.status].bg} ${statusColors[selectedAppointment.status].text}`}>
                                    {selectedAppointment.status.toUpperCase()}
                                </span>
                            </div>

                            <div className="space-y-2 text-sm text-gray-600">
                                <p className="flex items-center"><UserIcon className="w-4 h-4 mr-2" /> <strong>Patient:</strong>&nbsp;{getPatientName(selectedAppointment.patientId)}</p>
                                <p className="flex items-center"><UserIcon className="w-4 h-4 mr-2" /> <strong>Dentist:</strong>&nbsp;{getDentistName(selectedAppointment.dentistId)}</p>
                                <p className="flex items-center"><CalendarIcon className="w-4 h-4 mr-2" /> <strong>Date:</strong>&nbsp;{format(new Date(selectedAppointment.start), 'eeee, MMMM d, yyyy')}</p>
                                <p className="flex items-center"><ClockIcon className="w-4 h-4 mr-2" /> <strong>Time:</strong>&nbsp;{format(new Date(selectedAppointment.start), 'h:mm a')} - {format(new Date(selectedAppointment.end), 'h:mm a')}</p>
                            </div>
                        </div>

                        {selectedAppointment.status === AppointmentStatus.Pending && (
                            <div className="p-4 bg-amber-50 border border-amber-200 rounded-lg">
                                <p className="text-sm text-amber-800 font-medium mb-3">This appointment requires your approval before being officially scheduled.</p>
                                <button 
                                    onClick={handleApprove}
                                    disabled={isUpdating}
                                    className="w-full py-2 bg-amber-500 text-white font-bold rounded-md hover:bg-amber-600 shadow-md transition-colors"
                                >
                                    {isUpdating ? 'Approving...' : 'Approve Appointment'}
                                </button>
                            </div>
                        )}

                        <div className="border-t pt-4">
                            <label className="block text-sm font-medium text-gray-700 mb-2">Manual Status Override</label>
                            <div className="flex flex-wrap gap-2">
                                {[AppointmentStatus.Completed, AppointmentStatus.Cancelled, AppointmentStatus.NoShow].map(status => (
                                    <button
                                        key={status}
                                        onClick={() => handleStatusUpdate(status)}
                                        disabled={selectedAppointment.status === status || isUpdating}
                                        className={`px-3 py-1 rounded-md text-xs font-medium border ${
                                            selectedAppointment.status === status 
                                            ? 'bg-gray-100 text-gray-400 cursor-default border-gray-200' 
                                            : 'bg-white text-gray-700 hover:bg-gray-50 border-gray-300'
                                        }`}
                                    >
                                        {status.charAt(0).toUpperCase() + status.slice(1)}
                                    </button>
                                ))}
                            </div>
                        </div>
                         <div className="flex justify-end pt-2">
                            <button onClick={() => setSelectedAppointment(null)} className="text-gray-400 hover:text-gray-600 text-sm">Close</button>
                        </div>
                    </div>
                )}
            </Modal>

            <style>{`
                .custom-scrollbar::-webkit-scrollbar { width: 4px; }
                .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background-color: #CBD5E0; border-radius: 2px; }
            `}</style>
        </div>
    );
};

