                              <p className="flex items-center"><CalendarIcon className="w-4 h-4 mr-2 text-brand-blue"/> {format(new Date(app.start), 'eeee, MMM d')}</p>
                              <p className="flex items-center"><ClockIcon className="w-4 h-4 mr-2 text-brand-blue"/> {format(new Date(app.start), 'h:mm a')}</p>
                            </div>
                          </div>
                          <div className="mt-4 sm:mt-0 ml-0 sm:ml-4 flex gap-2">
                            <button onClick={() => handleCancelAppointment(app.id)} className="text-xs px-4 py-2 bg-gray-50 text-gray-500 rounded-lg hover:bg-red-50 hover:text-red-600 transition-colors">
                              {isPending ? 'Withdraw Request' : 'Cancel Appointment'}
                            </button>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-12 bg-white rounded-lg border-2 border-dashed border-gray-200">
                      <p className="text-gray-500 italic">No upcoming appointments found.</p>
                  </div>
                )}

                <h3 className="text-xl font-semibold text-gray-700 mt-10 mb-4">Patient History</h3>
                {pastAppointments.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                       {pastAppointments.map(app => (
                          <div key={app.id} className="bg-gray-50 p-3 rounded-lg border border-gray-100 opacity-80 flex justify-between items-center">
                             <div>
                                <p className="font-semibold text-gray-700">{services.find(s => s.id === app.serviceId)?.name}</p>
                                <p className="text-xs text-gray-500">{format(new Date(app.start), 'MMM d, yyyy')}</p>
                             </div>
                             <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded ${app.status === AppointmentStatus.Completed ? 'text-green-600 bg-green-50' : 'text-gray-400 bg-gray-100'}`}>
                                {app.status}
                             </span>
                          </div>
                       ))}
                    </div>
                ): (
                   <p className="text-sm text-gray-400">No past visits recorded.</p>
                )}
              </div>
            )}
          </>
        ) : (
          <Booking 
            user={user} 
            dentists={dentists}
            services={services}
            onBookingSuccess={handleBookingSuccess}
            onBack={() => setView('appointments')}
          />
        )}
      </main>
    </div>
  );
};

