const parseTime = (timeStr: string, baseDate: Date): Date => {
  const [hours, minutes] = timeStr.split(':').map(Number);
  const d = new Date(baseDate);
  d.setHours(hours, minutes, 0, 0);
  return d;
};

export const getAvailableTimeSlots = (date: Date, dentistId: string, serviceId: string): Promise<TimeSlot[]> => {
  clinicSettings = loadData(STORAGE_KEYS.SETTINGS, clinicSettings);
  dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);

  if (!clinicSettings.onlineBookingEnabled) return simulateDelay([]);

  const dentist = dentists.find(d => d.id === dentistId);
  const dayOfWeek = getDay(date);

  const hoursSource = (dentist?.workingHours && dentist.workingHours.length > 0) 
    ? dentist.workingHours 
    : clinicSettings.workingHours;

  const dayShifts = hoursSource.filter(wh => wh.dayOfWeek === dayOfWeek && wh.isOpen);
  const service = services.find(s => s.id === serviceId);

  if (dayShifts.length === 0 || !service) return simulateDelay([]);

  const dayString = format(date, 'yyyy-MM-dd');
  if(clinicSettings.holidays.includes(dayString)) return simulateDelay([]);

  const dentistAppointments = appointments.filter(a => 
    a.dentistId === dentistId && 
    isSameDay(a.start, date) && 
    (a.status === AppointmentStatus.Scheduled || a.status === AppointmentStatus.Pending)
  );

  const allSlots: TimeSlot[] = [];

  dayShifts.forEach(shift => {
    const startTime = parseTime(shift.start, date);
    const endTime = parseTime(shift.end, date);
    let currentTime = startTime;

    while(currentTime < endTime) {
        const slotEnd = addMinutes(currentTime, service.durationMinutes);
        if (slotEnd > endTime) break;

        const isBooked = dentistAppointments.some(appt => 
          (currentTime >= appt.start && currentTime < appt.end) ||
          (slotEnd > appt.start && slotEnd <= appt.end) ||
          (appt.start >= currentTime && appt.start < slotEnd)
        );

        allSlots.push({ time: new Date(currentTime.getTime()), isAvailable: !isBooked });
        currentTime = addMinutes(currentTime, clinicSettings.slotDurationMinutes);
    }
  });

  allSlots.sort((a, b) => a.time.getTime() - b.time.getTime());
  return simulateDelay(allSlots);
};

export const bookAppointment = (details: { patientId: string, dentistId: string, serviceId: string, start: Date }): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const service = services.find(s => s.id === details.serviceId);
  if (!service) throw new Error("Service not found");
  const newAppointment: Appointment = {
    id: `apt-${Date.now()}`,
    ...details,
    end: addMinutes(details.start, service.durationMinutes),
    status: AppointmentStatus.Pending,
    createdAt: new Date(),
    reminderSent: false,
    emailReminderSent: false,
    smsReminderSent: false
  };
  appointments.push(newAppointment);
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);

  // LOG BOOKING ACKNOWLEDGEMENT EMAIL
  const patient = users.find(u => u.id === details.patientId);
  if (patient) {
      sendVirtualEmail(
          patient.email, 
          "Booking Received - NexSched", 
          `Hi ${patient.name.split(' ')[0]}, we have received your request for ${service.name}. Our team will review it and notify you once confirmed.`
      );
  }

  return simulateDelay(newAppointment);
};

export const approveAppointment = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");

  appointments[index].status = AppointmentStatus.Scheduled;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);

  const patient = users.find(u => u.id === appointments[index].patientId);
  const dentist = dentists.find(d => d.id === appointments[index].dentistId);
  const service = services.find(s => s.id === appointments[index].serviceId);

  if (patient && dentist && service) {
    const timeStr = format(new Date(appointments[index].start), 'eeee, MMM d @ h:mm a');

    // THE EXACT EMAIL PROMPT REQUESTED
    const emailBody = `Hi ${patient.name}, Dr. ${dentist.name.split(' ').pop()} has reviewed and approved your booking for ${service.name} on ${timeStr}. Please arrive 10 minutes early. We look forward to seeing you!`;

    sendVirtualEmail(patient.email, "CONFIRMED: Your Appointment at NexSched", emailBody);
    alert(`[SYSTEM MESSAGE] Professional confirmation email dispatched to: ${patient.email}`);
  }

  return simulateDelay(appointments[index]);
};

export const cancelAppointment = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].status = AppointmentStatus.Cancelled;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const updateAppointmentStatus = (appointmentId: string, status: AppointmentStatus): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].status = status;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const sendSmsReminder = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].smsReminderSent = true;
  appointments[index].reminderSent = true;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const sendEmailReminder = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].emailReminderSent = true;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);

  const patient = users.find(u => u.id === appointments[index].patientId);
  const service = services.find(s => s.id === appointments[index].serviceId);
  if(patient && service) {
      sendVirtualEmail(
          patient.email, 
          "REMINDER: Appointment Tomorrow", 
          `Hi ${patient.name.split(' ')[0]}, this is a friendly reminder for your ${service.name} tomorrow at ${format(new Date(appointments[index].start), 'h:mm a')}. See you soon!`
      );
  }

  return simulateDelay(appointments[index]);
};

export const getReportData = (): Promise<ReportData> => {
    appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
    const total = appointments.length;
    const noShows = appointments.filter(a => a.status === AppointmentStatus.NoShow).length;
    const completed = appointments.filter(a => a.status === AppointmentStatus.Completed).length;
    const appointmentsByService = services.reduce((acc, service) => {
        acc[service.name] = appointments.filter(a => a.serviceId === service.id).length;
        return acc;
    }, {} as { [serviceName: string]: number });
    const dayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const busiestDays = appointments.reduce((acc, appt) => {
        const day = dayNames[getDay(appt.start)];
        acc[day] = (acc[day] || 0) + 1;
        return acc;
    }, {} as { [day: string]: number });
    return simulateDelay({
        totalAppointments: total,
        noShowRate: total > 0 ? (noShows / total) * 100 : 0,
        attendanceRate: total > 0 ? (completed / total) * 100 : 0,
        appointmentsByService,
        busiestDays
    });
};

import React, { useState } from 'react';
import { User, Appointment, VirtualEmail } from '../../types';
import { login, register, getAppointmentsForEmail, getEmailsForAddress } from '../../services/mockApi';
import Modal from '../Shared/Modal';
import { format } from 'date-fns';

interface LoginPageProps {
  onLogin: (user: User) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [showStatusModal, setShowStatusModal] = useState(false);

  // Common state
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Status Check State
  const [statusEmail, setStatusEmail] = useState('');
  const [statusResults, setStatusResults] = useState<{appts: Appointment[], emails: VirtualEmail[]} | null>(null);
  const [isCheckingStatus, setIsCheckingStatus] = useState(false);

  // Registration-specific state
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [age, setAge] = useState('');
  const [gender, setGender] = useState<'Male' | 'Female' | 'Other'>('Male');
  const [confirmPassword, setConfirmPassword] = useState('');


  const handleLoginSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    const user = await login(email, password);
    setIsLoading(false);

    if (user) {
      onLogin(user);
    } else {
      setError('Invalid email or password.');
    }
  };

  const handleRegisterSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if(password !== confirmPassword) {
        setError("Passwords do not match.");
        return;
    }
    setError('');
    setIsLoading(true);

    const result = await register({
        name,
        email,
        password_reg: password,
        phone,
        age: parseInt(age, 10),
        gender
    });

    setIsLoading(false);

    if (result.user) {
        onLogin(result.user);
    } else {
        setError(result.error || 'An unknown error occurred during registration.');
    }
  };

  const handleCheckStatus = async (e: React.FormEvent) => {
    e.preventDefault();
    if(!statusEmail) return;
    setIsCheckingStatus(true);
    const [appts, emails] = await Promise.all([
        getAppointmentsForEmail(statusEmail),
        getEmailsForAddress(statusEmail)
    ]);
    setStatusResults({ appts, emails });
    setIsCheckingStatus(false);
  };

  const toggleForm = () => {
    setIsRegistering(!isRegistering);
    setError('');
    setEmail('');
    setPassword('');
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-brand-gray-light py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md w-full space-y-8">
        <div>
          <div className="flex items-center justify-center">
             <svg className="h-12 w-12 text-brand-blue" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path>
            </svg>
          </div>
          <h2 className="mt-6 text-center text-3xl font-extrabold text-brand-blue-dark">
            {isRegistering ? 'Create Your Account' : 'Welcome to NexSched'}
          </h2>
        </div>

        {isRegistering ? (
             <form className="mt-8 space-y-4 bg-white p-8 rounded-lg shadow-lg" onSubmit={handleRegisterSubmit}>
                <div className="grid grid-cols-1 gap-y-4">
                    <input name="name" type="text" required className="input-field" placeholder="Full Name" value={name} onChange={e => setName(e.target.value)} />
                    <input name="email" type="email" required className="input-field" placeholder="Email Address" value={email} onChange={e => setEmail(e.target.value)} />
                    <input name="phone" type="tel" required className="input-field" placeholder="Phone Number" value={phone} onChange={e => setPhone(e.target.value)} />
                    <div className="grid grid-cols-2 gap-4">
                        <input name="age" type="number" required className="input-field" placeholder="Age" value={age} onChange={e => setAge(e.target.value)} />
                        <select name="gender" required className="input-field" value={gender} onChange={e => setGender(e.target.value as any)}>
                            <option>Male</option>
                            <option>Female</option>
                            <option>Other</option>
                        </select>
                    </div>
                    <input name="password" type="password" required className="input-field" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} />
                    <input name="confirmPassword" type="password" required className="input-field" placeholder="Confirm Password" value={confirmPassword} onChange={e => setConfirmPassword(e.target.value)} />
