import React, { useState, useEffect, useCallback } from 'react';
import { User, Appointment, Service, Dentist, AppointmentStatus, VirtualEmail } from '../../types';
import { getAppointmentsForUser, getServices, getDentists, cancelAppointment, sendSmsReminder, sendEmailReminder, getEmailsForAddress } from '../../services/mockApi';
import Header from '../Layout/Header';
import Booking from './Booking';
import { format, isSameDay, addDays } from 'date-fns';
import { CalendarIcon, ClockIcon, UserIcon } from '../Shared/Icons';
import Modal from '../Shared/Modal';

interface PatientDashboardProps {
  user: User;
  onLogout: () => void;
}

const PatientDashboard: React.FC<PatientDashboardProps> = ({ user, onLogout }) => {
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [dentists, setDentists] = useState<Dentist[]>([]);
  const [emails, setEmails] = useState<VirtualEmail[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [view, setView] = useState<'appointments' | 'booking'>('appointments');
  const [showInbox, setShowInbox] = useState(false);
  const [activeReminder, setActiveReminder] = useState<Appointment | null>(null);

  const fetchPatientData = useCallback(async () => {
    setIsLoading(true);
    try {
      const [userAppointments, allServices, allDentists, userEmails] = await Promise.all([
        getAppointmentsForUser(user.id),
        getServices(),
        getDentists(),
        getEmailsForAddress(user.email)
      ]);
      setAppointments(userAppointments);
      setServices(allServices);
      setDentists(allDentists);
      setEmails(userEmails);

      // SCAN FOR PENDING REMINDERS (Next 48 hours)
      const now = new Date();
      const next48h = addDays(now, 2);

      const pendingReminder = userAppointments.find(a => 
        a.status === AppointmentStatus.Scheduled && 
        new Date(a.start) > now && 
        new Date(a.start) <= next48h &&
        (!a.smsReminderSent || !a.emailReminderSent)
      );

      if (pendingReminder) {
          setActiveReminder(pendingReminder);
          setTimeout(async () => {
              // The reminder logic will now generate a "Sent Email" record in the system
              await sendEmailReminder(pendingReminder.id);
              await sendSmsReminder(pendingReminder.id);

              const updatedEmails = await getEmailsForAddress(user.email);
              const updatedAppts = await getAppointmentsForUser(user.id);
              setEmails(updatedEmails);
              setAppointments(updatedAppts);
          }, 1500);
      }
    } catch (error) {
      console.error("Failed to fetch patient data", error);
    } finally {
      setIsLoading(false);
    }
  }, [user.id, user.email]);

  useEffect(() => {
    fetchPatientData();
  }, [fetchPatientData]);

  const handleBookingSuccess = () => {
    fetchPatientData(); 
    setView('appointments');
  };

  const handleCancelAppointment = async (appointmentId: string) => {
    if (window.confirm("Are you sure you want to cancel this appointment?")) {
        await cancelAppointment(appointmentId);
        fetchPatientData();
        alert("Appointment cancelled. A notice was sent to your email.");
    }
  };

  const upcomingAppointments = appointments
    .filter(a => (a.status === AppointmentStatus.Scheduled || a.status === AppointmentStatus.Pending) && new Date(a.start) >= new Date())
    .sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

  const pastAppointments = appointments
    .filter(a => new Date(a.start) < new Date() || (a.status !== AppointmentStatus.Scheduled && a.status !== AppointmentStatus.Pending))
    .sort((a, b) => new Date(b.start).getTime() - new Date(a.start).getTime());

  return (
    <div>
      <Header user={user} onLogout={onLogout} />
      <main className="container mx-auto p-4 sm:p-6 lg:p-8">
        {view === 'appointments' ? (
          <>
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-gray-800">My Appointments</h2>
              <div className="flex gap-3">
                <button 
                  onClick={() => setShowInbox(true)} 
                  className="relative p-2 bg-white border border-gray-200 rounded-lg shadow-sm hover:bg-gray-50 text-gray-600 transition-colors"
                  title="My Inbox"
                >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"></path></svg>
                    {emails.length > 0 && <span className="absolute -top-1 -right-1 bg-red-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-full ring-2 ring-white">{emails.length}</span>}
                </button>
                <button onClick={() => setView('booking')} className="px-6 py-2 bg-brand-blue text-white font-semibold rounded-lg shadow-md hover:bg-brand-blue-dark">
                    Book New
                </button>
              </div>
            </div>

            {isLoading ? (
              <p>Syncing health records...</p>
            ) : (
              <div>
                <h3 className="text-xl font-semibold text-gray-700 mb-4">Active Schedule</h3>
                {upcomingAppointments.length > 0 ? (
                  <div className="space-y-4">
                    {upcomingAppointments.map(app => {
                      const dentist = dentists.find(d => d.id === app.dentistId);
                      const service = services.find(s => s.id === app.serviceId);
                      const isPending = app.status === AppointmentStatus.Pending;

                      return (
                        <div key={app.id} className="bg-white p-4 rounded-lg shadow-sm border border-gray-200 flex flex-col sm:flex-row justify-between items-start sm:items-center">
                          <div className="flex-1">
                            <div className="flex items-center gap-2 flex-wrap">
                              <p className="font-bold text-brand-blue-dark text-lg">{service?.name}</p>
                              {isPending ? (
                                <span className="px-2 py-0.5 bg-amber-100 text-amber-700 text-[10px] uppercase font-black rounded-full border border-amber-200">Awaiting Approval</span>
                              ) : (
                                <span className="px-2 py-0.5 bg-green-100 text-green-700 text-[10px] uppercase font-black rounded-full border border-green-200">Confirmed</span>
                              )}
                            </div>
                            <div className="text-gray-600 mt-2 grid grid-cols-1 sm:grid-cols-3 gap-2 text-sm">
                              <p className="flex items-center"><UserIcon className="w-4 h-4 mr-2 text-brand-blue"/> {dentist?.name}</p>
                              <p className="flex items-center"><CalendarIcon className="w-4 h-4 mr-2 text-brand-blue"/> {format(new Date(app.start), 'eeee, MMM d')}</p>
                              <p className="flex items-center"><ClockIcon className="w-4 h-4 mr-2 text-brand-blue"/> {format(new Date(app.start), 'h:mm a')}</p>
                            </div>
                          </div>
                          <div className="mt-4 sm:mt-0 ml-0 sm:ml-4 flex gap-2">
                            <button onClick={() => handleCancelAppointment(app.id)} className="text-xs px-4 py-2 bg-gray-50 text-gray-500 rounded-lg hover:bg-red-50 hover:text-red-600 transition-colors">
                              {isPending ? 'Withdraw Request' : 'Cancel'}
                            </button>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : (
                  <div className="text-center py-12 bg-white rounded-lg border-2 border-dashed border-gray-200">
                      <p className="text-gray-500 italic">No active schedules found.</p>
                  </div>
                )}

                <h3 className="text-xl font-semibold text-gray-700 mt-10 mb-4">Visit History</h3>
                {pastAppointments.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                       {pastAppointments.map(app => (
                          <div key={app.id} className="bg-gray-50 p-3 rounded-lg border border-gray-100 opacity-80 flex justify-between items-center">
                             <div>
                                <p className="font-semibold text-gray-700">{services.find(s => s.id === app.serviceId)?.name}</p>
                                <p className="text-xs text-gray-500">{format(new Date(app.start), 'MMM d, yyyy')}</p>
                             </div>
                             <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded ${app.status === AppointmentStatus.Completed ? 'text-green-600 bg-green-50' : 'text-gray-400 bg-gray-100'}`}>
                                {app.status}
                             </span>
                          </div>
                       ))}
                    </div>
                ): (
                   <p className="text-sm text-gray-400">No past visits recorded.</p>
                )}
              </div>
            )}

            <Modal isOpen={showInbox} onClose={() => setShowInbox(false)} title="Clinic Communications">
                <div className="space-y-4 max-h-96 overflow-y-auto pr-2 custom-scrollbar">
                    {emails.length === 0 ? (
                        <p className="text-center py-10 text-gray-500 italic">No messages found in your inbox.</p>
                    ) : (
                        emails.map(email => (
                            <div key={email.id} className="bg-blue-50/50 border border-blue-100 p-4 rounded-lg relative">
                                <p className="text-[10px] text-brand-blue-dark font-black uppercase mb-1">{format(new Date(email.timestamp), 'MMM d, yyyy @ h:mm a')}</p>
                                <h4 className="font-bold text-gray-800 mb-1">{email.subject}</h4>
                                <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">
                                    {email.body}
                                </p>
                            </div>
                        ))
                    )}
                </div>
            </Modal>
          </>
        ) : (
          <Booking 
            user={user} 
            dentists={dentists}
            services={services}
            onBookingSuccess={handleBookingSuccess}
            onBack={() => setView('appointments')}
          />
        )}
      </main>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background-color: #CBD5E0; border-radius: 2px; }
      `}</style>
    </div>
  );
};

export default PatientDashboard;

import { User, Appointment, Dentist, Service, ClinicSettings, TimeSlot, ReportData, AppointmentStatus, UserRole, VirtualEmail } from '../types';
import { MOCK_USERS, MOCK_APPOINTMENTS, MOCK_DENTISTS, MOCK_SERVICES, MOCK_CLINIC_SETTINGS } from '../constants';
import { getDay, format, addMinutes, isSameDay } from 'date-fns';

const STORAGE_KEYS = {
  USERS: 'nexsched_v18_users',
  APPOINTMENTS: 'nexsched_v18_appointments',
  SETTINGS: 'nexsched_v18_settings',
  DENTISTS: 'nexsched_v18_dentists',
  EMAILS: 'nexsched_v18_emails'
};

const loadData = <T,>(key: string, fallback: T): T => {
  try {
    const item = localStorage.getItem(key);
    if (item) {
      if (key === STORAGE_KEYS.APPOINTMENTS || key === STORAGE_KEYS.EMAILS) {
        return JSON.parse(item, (k, v) => {
           if (k === 'start' || k === 'end' || k === 'createdAt' || k === 'time' || k === 'timestamp') return new Date(v);
           return v;
        });
      }
      return JSON.parse(item);
    }
  } catch (e) {
    console.warn(`Failed to load ${key} from storage`, e);
  }
  return fallback;
};

const saveData = (key: string, data: any) => {
  try {
    localStorage.setItem(key, JSON.stringify(data));
  } catch (e) {
    console.error(`Failed to save ${key} to storage`, e);
  }
};

let users: User[] = loadData(STORAGE_KEYS.USERS, [...MOCK_USERS]);
let appointments: Appointment[] = loadData(STORAGE_KEYS.APPOINTMENTS, [...MOCK_APPOINTMENTS]);
let clinicSettings: ClinicSettings = loadData(STORAGE_KEYS.SETTINGS, { ...MOCK_CLINIC_SETTINGS });
let dentists: Dentist[] = loadData(STORAGE_KEYS.DENTISTS, [...MOCK_DENTISTS]);
let emails: VirtualEmail[] = loadData(STORAGE_KEYS.EMAILS, []);
let services: Service[] = [...MOCK_SERVICES];

let currentUserId: string | null = null;

const simulateDelay = <T,>(data: T): Promise<T> => {
  return new Promise(resolve => setTimeout(() => resolve(data), 400));
};

const sendVirtualEmail = (to: string, subject: string, body: string) => {
    emails = loadData(STORAGE_KEYS.EMAILS, emails);
    const newEmail: VirtualEmail = {
        id: `email-${Date.now()}`,
        to,
        subject,
        body,
        timestamp: new Date(),
        isRead: false
    };
    emails.push(newEmail);
    saveData(STORAGE_KEYS.EMAILS, emails);
};

export const getEmailsForAddress = (emailAddress: string): Promise<VirtualEmail[]> => {
    emails = loadData(STORAGE_KEYS.EMAILS, emails);
    return simulateDelay(emails.filter(e => e.to.toLowerCase() === emailAddress.toLowerCase()).sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime()));
};

export const login = (email: string, password: string): Promise<User | null> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  const user = users.find(u => u.email.toLowerCase() === email.toLowerCase() && u.password === password);
  if (user) {
    currentUserId = user.id;
    return simulateDelay(user);
  }
  return simulateDelay(null);
};

export const register = (details: Omit<User, 'id' | 'role' | 'password'> & { password_reg: string }): Promise<{ user: User | null; error?: string }> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  if (users.find(u => u.email.toLowerCase() === details.email.toLowerCase())) {
    return simulateDelay({ user: null, error: "An account with this email already exists." });
  }
  const newUser: User = {
    id: `user-${Date.now()}`,
    email: details.email,
    password: details.password_reg,
    name: details.name,
    phone: details.phone,
    age: details.age,
    gender: details.gender,
    role: UserRole.Patient,
  };
  users.push(newUser);
  saveData(STORAGE_KEYS.USERS, users);
  currentUserId = newUser.id;
  return simulateDelay({ user: newUser });
};

export const getCurrentUser = (): User | null => {
  if (!currentUserId) return null;
  return users.find(u => u.id === currentUserId) || null;
}

export const logout = (): void => {
  currentUserId = null;
};

export const getAppointmentsForEmail = (emailAddress: string): Promise<Appointment[]> => {
    appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
    users = loadData(STORAGE_KEYS.USERS, users);
    const user = users.find(u => u.email.toLowerCase() === emailAddress.toLowerCase());
    if (!user) return simulateDelay([]);
    return simulateDelay(appointments.filter(a => a.patientId === user.id));
};

export const getAppointmentsForUser = (userId: string): Promise<Appointment[]> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments.filter(a => a.patientId === userId));
};

export const getAllAppointments = (): Promise<Appointment[]> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments);
};

export const getAllPatients = (): Promise<User[]> => {
  users = loadData(STORAGE_KEYS.USERS, users);
  return simulateDelay(users.filter(u => u.role === 'patient'));
};

export const getDentists = (): Promise<Dentist[]> => {
  dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
  return simulateDelay(dentists);
};

export const getServices = (): Promise<Service[]> => simulateDelay(services);

export const getClinicSettings = (): Promise<ClinicSettings> => {
  clinicSettings = loadData(STORAGE_KEYS.SETTINGS, clinicSettings);
  return simulateDelay(clinicSettings);
};

export const updateClinicSettings = (settings: ClinicSettings): Promise<ClinicSettings> => {
    clinicSettings = { ...settings };
    saveData(STORAGE_KEYS.SETTINGS, clinicSettings);
    return simulateDelay(clinicSettings);
};

export const addDentist = (details: Omit<Dentist, 'id'>): Promise<Dentist> => {
    dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
    const newDentist: Dentist = {
        id: `dentist-${Date.now()}`,
        ...details
    };
    dentists.push(newDentist);
    saveData(STORAGE_KEYS.DENTISTS, dentists);
    return simulateDelay(newDentist);
};

export const deleteDentist = (id: string): Promise<void> => {
    dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
    dentists = dentists.filter(d => d.id !== id);
    saveData(STORAGE_KEYS.DENTISTS, dentists);
    return simulateDelay(undefined);
};

const parseTime = (timeStr: string, baseDate: Date): Date => {
  const [hours, minutes] = timeStr.split(':').map(Number);
  const d = new Date(baseDate);
  d.setHours(hours, minutes, 0, 0);
  return d;
};

export const getAvailableTimeSlots = (date: Date, dentistId: string, serviceId: string): Promise<TimeSlot[]> => {
  clinicSettings = loadData(STORAGE_KEYS.SETTINGS, clinicSettings);
  dentists = loadData(STORAGE_KEYS.DENTISTS, dentists);
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);

  if (!clinicSettings.onlineBookingEnabled) return simulateDelay([]);

  const dentist = dentists.find(d => d.id === dentistId);
  const dayOfWeek = getDay(date);

  const hoursSource = (dentist?.workingHours && dentist.workingHours.length > 0) 
    ? dentist.workingHours 
    : clinicSettings.workingHours;

  const dayShifts = hoursSource.filter(wh => wh.dayOfWeek === dayOfWeek && wh.isOpen);
  const service = services.find(s => s.id === serviceId);

  if (dayShifts.length === 0 || !service) return simulateDelay([]);

  const dayString = format(date, 'yyyy-MM-dd');
  if(clinicSettings.holidays.includes(dayString)) return simulateDelay([]);

  const dentistAppointments = appointments.filter(a => 
    a.dentistId === dentistId && 
    isSameDay(a.start, date) && 
    (a.status === AppointmentStatus.Scheduled || a.status === AppointmentStatus.Pending)
  );

  const allSlots: TimeSlot[] = [];

  dayShifts.forEach(shift => {
    const startTime = parseTime(shift.start, date);
    const endTime = parseTime(shift.end, date);
    let currentTime = startTime;

    while(currentTime < endTime) {
        const slotEnd = addMinutes(currentTime, service.durationMinutes);
        if (slotEnd > endTime) break;

        const isBooked = dentistAppointments.some(appt => 
          (currentTime >= appt.start && currentTime < appt.end) ||
          (slotEnd > appt.start && slotEnd <= appt.end) ||
          (appt.start >= currentTime && appt.start < slotEnd)
        );

        allSlots.push({ time: new Date(currentTime.getTime()), isAvailable: !isBooked });
        currentTime = addMinutes(currentTime, clinicSettings.slotDurationMinutes);
    }
  });

  allSlots.sort((a, b) => a.time.getTime() - b.time.getTime());
  return simulateDelay(allSlots);
};

export const bookAppointment = (details: { patientId: string, dentistId: string, serviceId: string, start: Date }): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const service = services.find(s => s.id === details.serviceId);
  if (!service) throw new Error("Service not found");
  const newAppointment: Appointment = {
    id: `apt-${Date.now()}`,
    ...details,
    end: addMinutes(details.start, service.durationMinutes),
    status: AppointmentStatus.Pending,
    createdAt: new Date(),
    reminderSent: false,
    emailReminderSent: false,
    smsReminderSent: false
  };
  appointments.push(newAppointment);
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);

  const patient = users.find(u => u.id === details.patientId);
  if (patient) {
      sendVirtualEmail(
          patient.email, 
          "Booking Request Received", 
          `Hi ${patient.name.split(' ')[0]}, we have received your request for ${service.name}. Our team will review it and notify you once it is officially confirmed.`
      );
  }

  return simulateDelay(newAppointment);
};

export const approveAppointment = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");

  appointments[index].status = AppointmentStatus.Scheduled;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);

  const patient = users.find(u => u.id === appointments[index].patientId);
  const dentist = dentists.find(d => d.id === appointments[index].dentistId);
  const service = services.find(s => s.id === appointments[index].serviceId);

  if (patient && dentist && service) {
    const timeStr = format(new Date(appointments[index].start), 'eeee, MMM d @ h:mm a');

    // EXACT PROMPT REQUESTED
    const emailBody = `Hi ${patient.name}, Dr. ${dentist.name.split(' ').pop()} has reviewed and approved your booking for ${service.name} on ${timeStr}. Please arrive 10 minutes early. We look forward to seeing you!`;

    sendVirtualEmail(patient.email, "CONFIRMED: Your Appointment at NexSched", emailBody);
  }

  return simulateDelay(appointments[index]);
};

export const cancelAppointment = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].status = AppointmentStatus.Cancelled;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const updateAppointmentStatus = (appointmentId: string, status: AppointmentStatus): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].status = status;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const sendSmsReminder = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].smsReminderSent = true;
  appointments[index].reminderSent = true;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);
  return simulateDelay(appointments[index]);
};

export const sendEmailReminder = (appointmentId: string): Promise<Appointment> => {
  appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
  const index = appointments.findIndex(a => a.id === appointmentId);
  if (index === -1) throw new Error("Appointment not found");
  appointments[index].emailReminderSent = true;
  saveData(STORAGE_KEYS.APPOINTMENTS, appointments);

  const patient = users.find(u => u.id === appointments[index].patientId);
  const dentist = dentists.find(d => d.id === appointments[index].dentistId);
  const service = services.find(s => s.id === appointments[index].serviceId);

  if(patient && dentist && service) {
      const timeStr = format(new Date(appointments[index].start), 'h:mm a');
      sendVirtualEmail(
          patient.email, 
          "Reminder: Your Dental Visit Tomorrow", 
          `Hi ${patient.name.split(' ')[0]}, this is a friendly reminder for your ${service.name} with Dr. ${dentist.name.split(' ').pop()} tomorrow at ${timeStr}. We look forward to seeing you!`
      );
  }

  return simulateDelay(appointments[index]);
};

export const getReportData = (): Promise<ReportData> => {
    appointments = loadData(STORAGE_KEYS.APPOINTMENTS, appointments);
    const total = appointments.length;
    const noShows = appointments.filter(a => a.status === AppointmentStatus.NoShow).length;
    const completed = appointments.filter(a => a.status === AppointmentStatus.Completed).length;
    const appointmentsByService = services.reduce((acc, service) => {
        acc[service.name] = appointments.filter(a => a.serviceId === service.id).length;
        return acc;
    }, {} as { [serviceName: string]: number });
    const dayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
    const busiestDays = appointments.reduce((acc, appt) => {
        const day = dayNames[getDay(appt.start)];
        acc[day] = (acc[day] || 0) + 1;
        return acc;
    }, {} as { [day: string]: number });
    return simulateDelay({
        totalAppointments: total,
        noShowRate: total > 0 ? (noShows / total) * 100 : 0,
        attendanceRate: total > 0 ? (completed / total) * 100 : 0,
        appointmentsByService,
        busiestDays
    });
};

import React, { useState, useMemo, useEffect } from 'react';
import { User, Dentist, Service, TimeSlot } from '../../types';
import { getAvailableTimeSlots, bookAppointment, register } from '../../services/mockApi';
import { format, endOfMonth, eachDayOfInterval, getDay, isToday, isBefore, addMonths } from 'date-fns';
import { ChevronLeftIcon, ChevronRightIcon } from '../Shared/Icons';
import Modal from '../Shared/Modal';

interface BookingProps {
    user?: User;
    dentists: Dentist[];
    services: Service[];
    onBookingSuccess: () => void;
    onBack?: () => void;
}

const Booking: React.FC<BookingProps> = ({ user, dentists, services, onBookingSuccess, onBack }) => {
    const [currentMonth, setCurrentMonth] = useState(new Date());
    const [selectedDate, setSelectedDate] = useState<Date | null>(null);
    const [selectedDentist, setSelectedDentist] = useState<string>(dentists[0]?.id || '');
    const [selectedService, setSelectedService] = useState<string>('');
    const [timeSlots, setTimeSlots] = useState<TimeSlot[]>([]);
    const [isLoadingSlots, setIsLoadingSlots] = useState(false);
    const [selectedTime, setSelectedTime] = useState<Date | null>(null);
    const [isConfirming, setIsConfirming] = useState(false);
    const [isBooking, setIsBooking] = useState(false);

    // Guest State
    const [guestDetails, setGuestDetails] = useState({
        name: '',
        email: '',
        phone: '',
        age: '',
        gender: 'Male'
    });

    const filteredServices = useMemo(() => {
        const dentist = dentists.find(d => d.id === selectedDentist);
        if (!dentist || !dentist.serviceIds) return services;
        return services.filter(s => dentist.serviceIds!.includes(s.id));
    }, [selectedDentist, dentists, services]);

    useEffect(() => {
        if (filteredServices.length > 0) {
            if (!selectedService || !filteredServices.find(s => s.id === selectedService)) {
                setSelectedService(filteredServices[0].id);
            }
        } else {
            setSelectedService('');
        }
    }, [filteredServices, selectedService]);

    const firstDayOfMonth = useMemo(() => new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1), [currentMonth]);
    const lastDayOfMonth = useMemo(() => endOfMonth(currentMonth), [currentMonth]);
    const daysInMonth = useMemo(() => eachDayOfInterval({ start: firstDayOfMonth, end: lastDayOfMonth }), [firstDayOfMonth, lastDayOfMonth]);
    const startingDayIndex = getDay(firstDayOfMonth);

    useEffect(() => {
        if (!selectedDentist && dentists.length > 0) setSelectedDentist(dentists[0].id);
    }, [dentists]);

    useEffect(() => {
        if (selectedDate && selectedDentist && selectedService) {
            const fetchSlots = async () => {
                setIsLoadingSlots(true);
                setTimeSlots([]);
                const slots = await getAvailableTimeSlots(selectedDate, selectedDentist, selectedService);
                setTimeSlots(slots);
                setIsLoadingSlots(false);
            };
            fetchSlots();
        }
    }, [selectedDate, selectedDentist, selectedService]);

    const todayStart = new Date();
    todayStart.setHours(0, 0, 0, 0);

    const handleDateClick = (day: Date) => {
        if (isBefore(day, todayStart)) return;
        setSelectedDate(day);
        setSelectedTime(null);
    };

    const handleBookAppointment = async () => {
        if (!selectedTime || !selectedDentist || !selectedService) return;

        setIsBooking(true);
        try {
            let bookingUserId = user?.id;
            let finalEmail = user?.email;

            if (!bookingUserId) {
                if (!guestDetails.name || !guestDetails.email || !guestDetails.phone || !guestDetails.age) {
                    alert("All fields are required to process your booking request.");
                    setIsBooking(false);
                    return;
                }

                const regResult = await register({
                    name: guestDetails.name,
                    email: guestDetails.email,
                    phone: guestDetails.phone,
                    age: parseInt(guestDetails.age) || 30,
                    gender: guestDetails.gender as any,
                    password_reg: 'Welcome123!'
                });

                if (regResult.error || !regResult.user) {
                    alert(regResult.error || "Request failed. Please try again.");
                    setIsBooking(false);
                    return;
                }
                bookingUserId = regResult.user.id;
                finalEmail = regResult.user.email;
            }

            await bookAppointment({
                patientId: bookingUserId!,
                dentistId: selectedDentist,
                serviceId: selectedService,
                start: selectedTime
            });

            alert(`REQUEST SUBMITTED\n\nYour appointment for ${services.find(s => s.id === selectedService)?.name} has been sent for approval. Check your Virtual Inbox at ${finalEmail} for the status update.`);

            onBookingSuccess();
        } catch (error) {
            console.error("Booking failed", error);
            alert("Failed to process request. Please try again.");
        } finally {
            setIsBooking(false);
            setIsConfirming(false);
        }
    };

    return (
        <div className="bg-white p-6 rounded-lg shadow-lg">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">Book Appointment</h2>
                {onBack && <button onClick={onBack} className="text-sm text-brand-blue hover:underline">Back to Dashboard</button>}
            </div>

            <div className="bg-amber-50 p-3 rounded-md mb-6 border border-amber-200 flex items-center gap-2">
                <svg className="w-5 h-5 text-amber-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
                <p className="text-xs text-amber-800 font-medium">All bookings require dentist approval. You will be notified via email once your visit is confirmed.</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                <div className="md:col-span-1 space-y-4">
                    <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Provider</label>
                        <select id="dentist" value={selectedDentist} onChange={e => setSelectedDentist(e.target.value)} className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-brand-blue focus:border-brand-blue sm:text-sm rounded-md shadow-sm">
                            {dentists.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">Requested Service</label>
                        <select id="service" value={selectedService} onChange={e => setSelectedService(e.target.value)} className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-brand-blue focus:border-brand-blue sm:text-sm rounded-md shadow-sm">
                            {filteredServices.length > 0 ? filteredServices.map(s => (
                                <option key={s.id} value={s.id}>{s.name}</option>
                            )) : <option value="">No services available</option>}
                        </select>
                    </div>
                </div>

                <div className="md:col-span-2">
                    <div className="flex items-center justify-between mb-4">
                        <button onClick={() => setCurrentMonth(addMonths(currentMonth, -1))} className="p-2 rounded-full hover:bg-gray-100"><ChevronLeftIcon className="w-5 h-5" /></button>
                        <h3 className="text-lg font-semibold">{format(currentMonth, 'MMMM yyyy')}</h3>
                        <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))} className="p-2 rounded-full hover:bg-gray-100"><ChevronRightIcon className="w-5 h-5" /></button>
                    </div>
                    <div className="grid grid-cols-7 gap-1 text-center text-xs text-gray-500 font-bold">
                        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => <div key={day}>{day}</div>)}
                    </div>
                    <div className="grid grid-cols-7 gap-1 mt-2">
                        {Array.from({ length: startingDayIndex }).map((_, i) => <div key={`empty-${i}`} />)}
                        {daysInMonth.map(day => {
                            const isPast = isBefore(day, todayStart);
                            const isSelected = selectedDate && format(day, 'yyyy-MM-dd') === format(selectedDate, 'yyyy-MM-dd');
                            return (
                                <div key={day.toString()} className="flex justify-center items-center">
                                    <button 
                                        onClick={() => handleDateClick(day)}
                                        disabled={isPast}
                                        className={`w-10 h-10 rounded-lg transition-all duration-200 border ${
                                            isPast ? 'text-gray-300 border-transparent cursor-not-allowed' : 
                                            isSelected ? 'bg-brand-blue text-white border-brand-blue shadow-md' :
                                            isToday(day) ? 'text-brand-blue font-black border-brand-blue/20' : 'hover:bg-brand-blue-light border-gray-50'
                                        }`}
                                    >
                                        {format(day, 'd')}
                                    </button>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {selectedDate && (
                <div className="mt-8">
                    <h3 className="text-lg font-semibold mb-4">Available Times: {format(selectedDate, 'MMM d, yyyy')}</h3>
                    {isLoadingSlots ? <p className="text-sm animate-pulse text-gray-400">Checking schedule...</p> : (
                        <div className="grid grid-cols-3 sm:grid-cols-4 md:grid-cols-6 gap-2">
                            {timeSlots.filter(s => s.isAvailable).length > 0 ? timeSlots.filter(s => s.isAvailable).map(slot => (
                                <button
                                    key={slot.time.toISOString()}
                                    onClick={() => setSelectedTime(slot.time)}
                                    className={`p-2 rounded-md text-sm font-medium border transition-all ${selectedTime?.getTime() === slot.time.getTime() ? 'bg-brand-blue text-white border-brand-blue shadow-inner' : 'bg-white hover:border-brand-blue text-gray-700'}`}
                                >
                                    {format(slot.time, 'h:mm a')}
                                </button>
                            )) : <p className="col-span-full text-gray-500 italic">No slots available for this date.</p>}
                        </div>
                    )}
                </div>
            )}

            {selectedTime && (
                <div className="mt-8 flex justify-end">
                    <button onClick={() => setIsConfirming(true)} className="px-8 py-3 bg-brand-blue text-white font-bold rounded-lg shadow-lg hover:bg-brand-blue-dark transition-all transform hover:scale-105 active:scale-95">
                        {user ? 'Request Appointment' : 'Next: Contact Info'}
                    </button>
                </div>
            )}

            <Modal isOpen={isConfirming} onClose={() => setIsConfirming(false)} title="Request Booking">
                <div className="space-y-4">
                    <div className="bg-gray-50 p-4 rounded-lg border border-gray-200">
                        <p className="text-xs font-black text-gray-400 uppercase mb-2">Selected Visit</p>
                        <p className="text-sm"><strong>Treatment:</strong> {services.find(s => s.id === selectedService)?.name}</p>
                        <p className="text-sm"><strong>Provider:</strong> {dentists.find(d => d.id === selectedDentist)?.name}</p>
                        <p className="text-sm"><strong>Date/Time:</strong> {selectedDate && format(selectedDate, 'MMM d')} @ {selectedTime && format(selectedTime, 'h:mm a')}</p>
                    </div>

                    {!user && (
                        <div className="pt-2">
                            <h4 className="font-bold text-gray-800 mb-2">Notification Details</h4>
                            <p className="text-[10px] text-gray-500 mb-3 uppercase font-bold tracking-widest">Reminders will be sent to this email only</p>
                            <div className="space-y-3">
                                <input 
                                    type="text" 
                                    placeholder="Full Name" 
                                    className="w-full border p-2 rounded text-sm"
                                    value={guestDetails.name} 
                                    onChange={e => setGuestDetails({...guestDetails, name: e.target.value})}
                                />
                                <input 
                                    type="email" 
                                    placeholder="Email Address" 
                                    className="w-full border p-2 rounded text-sm"
                                    value={guestDetails.email} 
                                    onChange={e => setGuestDetails({...guestDetails, email: e.target.value})}
                                />
                                <input 
                                    type="tel" 
                                    placeholder="Phone (for SMS alerts)" 
                                    className="w-full border p-2 rounded text-sm"
                                    value={guestDetails.phone} 
                                    onChange={e => setGuestDetails({...guestDetails, phone: e.target.value})}
                                />
                                <div className="grid grid-cols-2 gap-2">
                                    <input 
                                        type="number" 
                                        placeholder="Age" 
                                        className="w-full border p-2 rounded text-sm"
                                        value={guestDetails.age} 
                                        onChange={e => setGuestDetails({...guestDetails, age: e.target.value})}
                                    />
                                    <select 
                                        className="w-full border p-2 rounded text-sm"
                                        value={guestDetails.gender} 
                                        onChange={e => setGuestDetails({...guestDetails, gender: e.target.value})}
                                    >
                                        <option>Male</option>
                                        <option>Female</option>
                                    </select>
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="flex justify-end gap-3 mt-8">
                        <button onClick={() => setIsConfirming(false)} className="px-4 py-2 text-gray-500 font-semibold">Cancel</button>
                        <button onClick={handleBookAppointment} disabled={isBooking} className="px-6 py-2 bg-brand-blue text-white rounded-md font-bold disabled:bg-gray-400">
                            {isBooking ? 'Processing...' : 'Submit Request'}
                        </button>
                    </div>
                </div>
            </Modal>
        </div>
    );
};

export default Booking;

import React, { useState, useEffect } from 'react';
import { Appointment, AppointmentStatus, User, Service, VirtualEmail } from '../../types';
import { getAllAppointments, getAllPatients, getServices, sendSmsReminder, sendEmailReminder, getEmailsForAddress } from '../../services/mockApi';
import { format, addDays } from 'date-fns';
import Modal from '../Shared/Modal';

const Reminders: React.FC = () => {
    const [appointments, setAppointments] = useState<Appointment[]>([]);
    const [patients, setPatients] = useState<User[]>([]);
    const [services, setServices] = useState<Service[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [selectedEmail, setSelectedEmail] = useState<VirtualEmail | null>(null);

    const fetchReminderData = async () => {
        setIsLoading(true);
        try {
            const [apptData, patientData, serviceData] = await Promise.all([
                getAllAppointments(),
                getAllPatients(),
                getServices()
            ]);

            const now = new Date();
            const weekOut = addDays(now, 7);

            const upcoming = apptData.filter(a => 
                (a.status === AppointmentStatus.Scheduled || a.status === AppointmentStatus.Pending) &&
                new Date(a.start) >= now &&
                new Date(a.start) <= weekOut
            );

            upcoming.sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

            setAppointments(upcoming);
            setPatients(patientData);
            setServices(serviceData);
        } catch (error) {
            console.error("Failed to load reminder data", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchReminderData();
    }, []);

    const handleViewSentMessage = async (emailAddress: string) => {
        const msgs = await getEmailsForAddress(emailAddress);
        if (msgs.length > 0) {
            setSelectedEmail(msgs[0]); // Show latest
        } else {
            alert("No messages have been dispatched to this user yet.");
        }
    };

    const handleReSend = async (appointment: Appointment, channel: 'SMS' | 'EMAIL') => {
        const patient = patients.find(p => p.id === appointment.patientId);
        const service = services.find(s => s.id === appointment.serviceId);
        if (!patient) return;

        if (channel === 'SMS') {
            await sendSmsReminder(appointment.id);
            alert(`SMS reminder triggered for ${patient.name}`);
        } else {
            await sendEmailReminder(appointment.id);
            alert(`Email reminder triggered for ${patient.name}`);
        }
        fetchReminderData();
    };

    if (isLoading) return <p className="p-4 text-gray-400">Checking delivery logs...</p>;

    return (
        <div className="bg-white p-6 rounded-lg shadow-lg">
            <div className="flex justify-between items-center mb-6">
                <div>
                    <h2 className="text-2xl font-bold text-gray-800">Notification Hub</h2>
                    <p className="text-sm text-gray-500">Monitoring outgoing messages and reminders</p>
                </div>
                <button onClick={fetchReminderData} className="px-4 py-2 bg-gray-50 text-brand-blue-dark rounded-md text-sm font-semibold hover:bg-gray-100 border border-brand-blue/10">
                    Refresh Logs
                </button>
            </div>

            {appointments.length === 0 ? (
                <div className="text-center py-10 bg-gray-50 rounded-lg border-2 border-dashed border-gray-200">
                    <p className="text-gray-500">No active visits requiring notifications in the next 7 days.</p>
                </div>
            ) : (
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Patient & Service</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Schedule</th>
                                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase">Channel Status</th>
                                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {appointments.map(appt => {
                                const patient = patients.find(p => p.id === appt.patientId);
                                const service = services.find(s => s.id === appt.serviceId);

                                return (
                                    <tr key={appt.id} className="hover:bg-gray-50 transition-colors">
                                        <td className="px-6 py-4">
                                            <div className="text-sm font-bold text-gray-900">{patient?.name || 'Guest'}</div>
                                            <div className="text-[10px] text-gray-400 font-mono uppercase tracking-tight">{patient?.email}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm text-gray-900 font-semibold">{format(new Date(appt.start), 'MMM d, h:mm a')}</div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col items-center gap-1">
                                                <div className="flex gap-2">
                                                    <span className={`px-2 py-0.5 text-[9px] font-black uppercase rounded ${appt.emailReminderSent ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-400'}`}>Email</span>
                                                    <span className={`px-2 py-0.5 text-[9px] font-black uppercase rounded ${appt.smsReminderSent ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-400'}`}>SMS</span>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-right space-x-3">
                                            <button 
                                                onClick={() => handleViewSentMessage(patient?.email || '')} 
                                                className="text-[10px] font-black uppercase text-brand-blue hover:underline"
                                            >
                                                Preview Message
                                            </button>
                                            <button 
                                                onClick={() => handleReSend(appt, 'EMAIL')} 
                                                className="text-[10px] font-black uppercase text-gray-400 hover:text-brand-blue"
                                            >
                                                Resend
                                            </button>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            )}

            <Modal isOpen={!!selectedEmail} onClose={() => setSelectedEmail(null)} title="Email Content Verification">
                {selectedEmail && (
                    <div className="space-y-4">
                        <div className="p-3 bg-gray-50 border rounded-lg">
                            <p className="text-[10px] text-gray-400 uppercase font-black mb-1">Recipient</p>
                            <p className="text-sm font-bold">{selectedEmail.to}</p>
                        </div>
                        <div className="p-3 bg-blue-50/50 border border-blue-100 rounded-lg">
                            <p className="text-[10px] text-brand-blue uppercase font-black mb-1">Subject</p>
                            <p className="text-sm font-bold text-brand-blue-dark">{selectedEmail.subject}</p>
                        </div>
                        <div className="p-4 bg-white border border-gray-200 rounded-lg shadow-inner">
                            <p className="text-[10px] text-gray-400 uppercase font-black mb-2 border-b pb-1">Message Body</p>
                            <p className="text-sm text-gray-700 leading-relaxed italic">
                                "{selectedEmail.body}"
                            </p>
                        </div>
