/**
 * Speech Service
 * Using native Web Speech API (SpeechSynthesis) to provide 
 * accessible voice feedback without external API dependencies.
 */

export const speakText = (text: string) => {
  if (!('speechSynthesis' in window)) {
    console.warn("Speech synthesis not supported in this browser.");
    return;
  }

  // Cancel any ongoing speech
  window.speechSynthesis.cancel();

  const utterance = new SpeechSynthesisUtterance(text);

  // Configure for a professional, clear sound
  utterance.rate = 0.95; // Slightly slower for clarity
  utterance.pitch = 1.0;
  utterance.volume = 1.0;

  // Try to find a nice local voice (optional, defaults to system)
  const voices = window.speechSynthesis.getVoices();
  const preferredVoice = voices.find(v => v.lang.startsWith('en') && v.name.includes('Google')) 
    || voices.find(v => v.lang.startsWith('en')) 
    || voices[0];

  if (preferredVoice) {
    utterance.voice = preferredVoice;
  }

  window.speechSynthesis.speak(utterance);
};

import React, { useState, useCallback } from 'react';
import { User, UserRole } from './types';
import LoginPage from './components/Auth/LoginPage';
import PatientDashboard from './components/Patient/PatientDashboard';
import AdminDashboard from './components/Admin/AdminDashboard';
import PublicBooking from './components/Public/PublicBooking';
import { getCurrentUser, logout } from './services/mockApi';

const App: React.FC = () => {
  const isPublicBooking = window.location.pathname.startsWith('/book');
  const [currentUser, setCurrentUser] = useState<User | null>(getCurrentUser());

  const handleLogin = useCallback((user: User) => {
    setCurrentUser(user);
  }, []);

  const handleLogout = useCallback(() => {
    logout();
    setCurrentUser(null);
  }, []);

  if (isPublicBooking) {
    return (
        <div className="bg-brand-gray-light min-h-screen font-sans text-gray-800">
            <PublicBooking />
        </div>
    );
  }

  const renderContent = () => {
    if (!currentUser) {
      return <LoginPage onLogin={handleLogin} />;
    }

    switch (currentUser.role) {
      case UserRole.Patient:
        return <PatientDashboard user={currentUser} onLogout={handleLogout} />;
      case UserRole.Admin:
        return <AdminDashboard user={currentUser} onLogout={handleLogout} />;
      default:
        return <LoginPage onLogin={handleLogin} />;
    }
  };

  return (
    <div className="bg-brand-gray-light min-h-screen font-sans text-gray-800">
      {renderContent()}
    </div>
  );
};

export default App;
